    setFormData: (val: any) => void;
    handleSubmit: (e: React.FormEvent) => void;
    loading: boolean;
}

const ParcelForm: React.FC<ParcelFormProps> = ({ 
    isOpen, onClose, editingId, formData, setFormData, handleSubmit, loading 
}) => {
    const fileInputRef = useRef<HTMLInputElement>(null);
    const canvasRef = useRef<HTMLCanvasElement>(null);

    const drawPreview = useCallback(() => {
        if (!canvasRef.current || !formData.geometry) return;
        const canvas = canvasRef.current;
        const ctx = canvas.getContext('2d');
        if (!ctx) return;

        let rawCoords: any[] = [];
        if (formData.geometry.type === 'Polygon') rawCoords = formData.geometry.coordinates[0];
        else if (formData.geometry.type === 'MultiPolygon') rawCoords = formData.geometry.coordinates[0][0];

        if (rawCoords.length === 0) return;
        const points = rawCoords.map(c => ({ x: c[0], y: c[1] }));
        const xs = points.map(p => p.x), ys = points.map(p => p.y);
        const minX = Math.min(...xs), maxX = Math.max(...xs), minY = Math.min(...ys), maxY = Math.max(...ys);
        const rangeX = maxX - minX || 0.000001, rangeY = maxY - minY || 0.000001;
        const padding = 20;
        const scale = Math.min((canvas.width - padding * 2) / rangeX, (canvas.height - padding * 2) / rangeY);

        ctx.clearRect(0, 0, canvas.width, canvas.height);
        ctx.beginPath();
        ctx.strokeStyle = '#3b82f6';
        ctx.fillStyle = 'rgba(59, 130, 246, 0.1)';
        points.forEach((pt, i) => {
            const px = (canvas.width / 2) + (pt.x - (minX + maxX) / 2) * scale;
            const py = (canvas.height / 2) - (pt.y - (minY + maxY) / 2) * scale;
            if (i === 0) ctx.moveTo(px, py); else ctx.lineTo(px, py);
        });
        ctx.closePath(); ctx.fill(); ctx.stroke();
    }, [formData.geometry]);

