                        </div>
                        <div className="space-y-1.5"><label className="text-[10px] font-black text-gray-500 uppercase tracking-widest">Chủ sở hữu</label><input className="w-full bg-gray-950 border border-gray-700 rounded-xl p-2.5 text-sm focus:border-blue-500 outline-none font-bold text-white" value={formData.tenchu||''} onChange={e=>setFormData({...formData, tenchu: e.target.value})} /></div>
                        <div className="grid grid-cols-2 gap-4">
