import express from 'express';
import os from 'os';

export default function(pool, logSystemAction, dbConfig) {
    const router = express.Router();

    // --- WMS LAYERS ---
    router.get('/wms-layers', async (req, res) => {
        try { res.json((await pool.query(`SELECT * FROM wms_layers`)).rows); } catch (e) { res.status(500).json({ error: e.message }); }
    });

    // --- BASEMAPS ---
    router.get('/basemaps', async (req, res) => {
        try { res.json((await pool.query(`SELECT id, name, url, type, is_default as "isDefault", visible FROM basemaps`)).rows); } catch (e) { res.status(500).json({ error: e.message }); }
    });

    // --- ROLE PERMISSIONS ---
    router.get('/role-permissions', async (req, res) => {
        try { res.json((await pool.query(`SELECT role, permissions FROM role_permissions`)).rows); } catch (e) { res.status(500).json({ error: e.message }); }
    });
    router.post('/role-permissions', async (req, res) => {
        try {
            await pool.query(`INSERT INTO role_permissions (role, permissions) VALUES ($1, $2) ON CONFLICT (role) DO UPDATE SET permissions = EXCLUDED.permissions`, [req.body.role, req.body.permissions]);
            res.json({ status: 'ok' });
        } catch (e) { res.status(500).json({ error: e.message }); }
    });

    // --- SYSTEM LOGS ---
    router.get('/logs', async (req, res) => {
        try { res.json((await pool.query(`SELECT id, user_id as "userId", user_name as "userName", action, details, timestamp FROM system_logs ORDER BY timestamp DESC LIMIT 200`)).rows); } catch (e) { res.status(500).json({ error: e.message }); }
    });

    // --- DB STATUS & SERVER INFO ---
    router.get('/db-check', async (req, res) => {
        try { await pool.query('SELECT 1'); res.json({ status: 'connected', dbName: dbConfig.database, host: dbConfig.host }); } catch (e) { res.json({ status: 'error', message: e.message }); }
    });
    router.get('/server-info', (req, res) => {
        res.json({ osType: os.type(), uptime: os.uptime(), freeMem: os.freemem(), cpuUsage: 0 });
    });

    // --- BACKUP V2: DANH SÁCH BẢNG ---
    router.get('/backup/tables', async (req, res) => {
        try {
            // Lấy danh sách bảng hệ thống và bảng trong registry
            const systemTables = [
                'users', 'branches', 'system_settings', 'land_prices', 
                'menu_items', 'wms_layers', 'basemaps', 'role_permissions', 
                'system_notifications', 'spatial_tables_registry'
            ];

            const registryRes = await pool.query(`SELECT table_name FROM spatial_tables_registry`);
            const spatialTables = registryRes.rows.map(r => r.table_name);

            res.json({
                system: systemTables,
                spatial: spatialTables
            });
        } catch (e) { res.status(500).json({ error: e.message }); }
    });

    // --- BACKUP V2: TẠO FILE SQL ---
    router.post('/backup/create', async (req, res) => {
        const { tables } = req.body;
        if (!tables || !Array.isArray(tables) || tables.length === 0) {
            return res.status(400).json({ error: "Vui lòng chọn ít nhất một bảng để sao lưu." });
        }

        try {
            let sqlDump = `-- GeoMaster WebGIS SQL Dump\n`;
            sqlDump += `-- Date: ${new Date().toISOString()}\n`;
            sqlDump += `-- Database: ${dbConfig.database}\n\n`;
            sqlDump += `SET statement_timeout = 0;\nSET lock_timeout = 0;\nSET client_encoding = 'UTF8';\nSET standard_conforming_strings = on;\nSELECT pg_catalog.set_config('search_path', '', false);\n\n`;

            for (const table of tables) {
                // Lấy thông tin cột
                const colRes = await pool.query(
                    `SELECT column_name, data_type 
                     FROM information_schema.columns 
                     WHERE table_name = $1 
                     ORDER BY ordinal_position`, 
                    [table]
                );

                if (colRes.rows.length === 0) continue;

                const columns = colRes.rows.map(r => r.column_name);
                const colString = columns.map(c => `"${c}"`).join(', ');

                // Lấy dữ liệu (Xử lý Geometry sang EWKT nếu là cột hình học)
                const dataQuery = `
                    SELECT ${colRes.rows.map(r => {
                        if (r.data_type === 'USER-DEFINED') return `ST_AsEWKT("${r.column_name}") as "${r.column_name}"`;
                        return `"${r.column_name}"`;
                    }).join(', ')} 
                    FROM "${table}"
                `;

                const dataRes = await pool.query(dataQuery);

                sqlDump += `-- Data for table: ${table}\n`;
                sqlDump += `DELETE FROM "${table}";\n`; // Xóa dữ liệu cũ trước khi nạp lại (tùy chọn)

                for (const row of dataRes.rows) {
                    const values = columns.map(col => {
                        const val = row[col];
                        if (val === null) return 'NULL';
                        if (typeof val === 'string') {
                            // Nếu là EWKT (bắt đầu bằng SRID=), bọc trong hàm PostGIS
                            if (val.startsWith('SRID=')) return `ST_GeomFromEWKT('${val.replace(/'/g, "''")}')`;
                            return `'${val.replace(/'/g, "''")}'`;
                        }
                        if (val instanceof Date) return `'${val.toISOString()}'`;
                        if (Array.isArray(val)) return `'${JSON.stringify(val)}'`;
                        return val;
                    });
                    sqlDump += `INSERT INTO "${table}" (${colString}) VALUES (${values.join(', ')});\n`;
                }
                sqlDump += `\n`;
            }

            res.setHeader('Content-disposition', `attachment; filename=geomaster_backup_${Date.now()}.sql`);
            res.setHeader('Content-type', 'text/plain');
            res.send(sqlDump);

            await logSystemAction(req, 'BACKUP_SQL', `Sao lưu ${tables.length} bảng dữ liệu`);
        } catch (e) { 
            console.error("Backup Error:", e);
            res.status(500).json({ error: "Lỗi tạo file sao lưu: " + e.message }); 
        }
    });

    return router;
}

import { User, UserRole, Branch, LandParcel, DashboardStats, SystemLog, LandPriceConfig, WMSLayerConfig, SystemSetting, RoleConfig, PermissionDefinition, BasemapConfig, MenuItem, Message, SystemNotification } from '../types';

const getApiUrl = () => {
    const { hostname, protocol } = window.location;

    const isLocal = 
        hostname === 'localhost' || 
        hostname === '127.0.0.1' || 
        hostname.startsWith('192.168.') || 
        hostname.startsWith('10.') || 
        hostname.startsWith('172.');

    if (isLocal) {
        return `${protocol}//${hostname}:3004`;
    }

    return 'https://apigeo.gisvn.space'; 
};

export const API_URL = getApiUrl();

const getAuthHeaders = () => {
    const headers: any = {};
    const userStr = localStorage.getItem('geo_user');
    if (userStr) {
        try {
            const u = JSON.parse(userStr);
            headers['x-user-id'] = u.id;
            headers['x-user-name'] = encodeURIComponent(u.name);
            headers['x-branch-id'] = u.branchId || u.branch_id;
        } catch (e) {}
    }
    return headers;
};

const apiCall = async (endpoint: string, options?: RequestInit) => {
    const cleanEndpoint = endpoint.startsWith('/api') ? endpoint : `/api${endpoint}`;
    const finalUrl = `${API_URL}${cleanEndpoint}`;

    try {
        const headers: any = { 'Content-Type': 'application/json', ...getAuthHeaders(), ...options?.headers };

        if (options?.body instanceof FormData) delete headers['Content-Type'];

        const res = await fetch(finalUrl, { ...options, headers });
        const responseText = await res.text();

        let responseData: any = null;
        if (responseText) {
            try { responseData = JSON.parse(responseText); } catch (e) {}
        }

        if (!res.ok) {
            let errorMessage = `Lỗi hệ thống (${res.status})`;
            if (responseData && (responseData.error || responseData.message)) {
                errorMessage = responseData.error || responseData.message;
            }
            throw new Error(errorMessage);
        }

        return responseData || { status: 'ok' };
    } catch (error: any) {
        throw error;
    }
};

