    resetPassword: async (id: string, password: string) => await apiCall(`/users/${id}/reset-password`, { method: 'PUT', body: JSON.stringify({ password }) }),
    deleteUser: async (id: string) => await apiCall(`/users/${id}`, { method: 'DELETE' }),
    toggleChatRestriction: async (userId: string, canChat: boolean) => await apiCall(`/users/${userId}/chat-restriction`, { method: 'PUT', body: JSON.stringify({ canChat }) }),
    getBranches: async () => await apiCall('/branches'),
    addBranch: async (branch: any) => await apiCall('/branches', { method: 'POST', body: JSON.stringify(branch) }),
    updateBranch: async (branch: any) => await apiCall(`/branches/${branch.id}`, { method: 'PUT', body: JSON.stringify(branch) }),
    deleteBranch: async (id: string) => await apiCall(`/branches/${id}`, { method: 'DELETE' }),
    getSettings: async () => await apiCall('/settings'),
    saveSettings: async (settings: SystemSetting[]) => await apiCall('/settings', { method: 'POST', body: JSON.stringify({ settings }) }),
    getWmsLayers: async () => await apiCall('/wms-layers'),
    addWmsLayer: async (layer: any) => await apiCall('/wms-layers', { method: 'POST', body: JSON.stringify(layer) }),
    updateWmsLayer: async (layer: any) => await apiCall(`/wms-layers/${layer.id}`, { method: 'PUT', body: JSON.stringify(layer) }),
    deleteWmsLayer: async (id: string) => await apiCall(`/wms-layers/${id}`, { method: 'DELETE' }),
    getBasemaps: async () => await apiCall('/basemaps'),
    addBasemap: async (bm: any) => await apiCall('/basemaps', { method: 'POST', body: JSON.stringify(bm) }),
    updateBasemap: async (bm: any) => await apiCall(`/basemaps/${bm.id}`, { method: 'PUT', body: JSON.stringify(bm) }),
    deleteBasemap: async (id: string) => await apiCall(`/basemaps/${id}`, { method: 'DELETE' }),
    getLogs: async () => await apiCall('/logs'),
    getRolePermissions: async () => await apiCall('/role-permissions'),
    saveRolePermissions: async (role: UserRole, permissions: string[]) => await apiCall('/role-permissions', { method: 'POST', body: JSON.stringify({ role, permissions }) }),
    getPrices: async () => await apiCall('/land-prices'),
    addPrice: async (price: any) => await apiCall('/land-prices', { method: 'POST', body: JSON.stringify(price) }),
    updatePrice: async (price: any) => await apiCall(`/land-prices/${price.landType}`, { method: 'PUT', body: JSON.stringify(price) }),
    deletePrice: async (landType: string) => await apiCall(`/land-prices/${landType}`, { method: 'DELETE' }),

    getBackupTables: async () => await apiCall('/backup/tables'),

    createBackup: async (tables: string[]) => {
        try {
            const res = await fetch(`${API_URL}/api/backup/create`, { 
                method: 'POST',
                headers: { ...getAuthHeaders(), 'Content-Type': 'application/json' },
                body: JSON.stringify({ tables })
            });
            if (!res.ok) throw new Error("Tạo bản sao lưu thất bại");
            const blob = await res.blob();
            const url = window.URL.createObjectURL(blob);
            const a = document.createElement('a');
            a.href = url;
            a.download = `backup_${Date.now()}.sql`;
            a.click();
        } catch (e: any) {
            throw e;
        }
    },

    restoreDatabase: async (file: File) => {
        const formData = new FormData();
        formData.append('file', file);
        return await apiCall('/backup/restore', { method: 'POST', body: formData });
    }
};

