                                </div>
                            </div>
                            <input type="file" accept=".sql" className="hidden" ref={backupInputRef} onChange={e => { const file = e.target.files?.[0]; if(file) { setLoading(true); adminService.restoreDatabase(file).then(()=>showDialog('success', 'Phục hồi', 'Hệ thống đã nạp lại dữ liệu thành công.')).catch(err=>showDialog('error', 'Lỗi phục hồi', err.message)).finally(()=>setLoading(false)); }}} />
                            <button onClick={() => backupInputRef.current?.click()} disabled={loading} className="bg-orange-600 hover:bg-orange-500 text-white py-3 rounded-2xl font-black uppercase text-xs tracking-widest flex items-center justify-center gap-2 transition-all active:scale-95">
                                {loading ? <RefreshCw className="animate-spin" size={16}/> : <ImageIcon size={16}/>} Chọn file .sql để phục hồi
                            </button>
                        </div>
                    </div>
                )}

                <div className="mt-8 flex justify-end gap-3 pt-6 border-t border-gray-700">
                    <button onClick={loadData} className="px-4 py-2 text-gray-400 hover:text-white font-bold uppercase text-[10px] tracking-widest">Làm mới</button>
                    {subTab !== 'BACKUP' && (
                        <button onClick={handleSave} disabled={loading} className="bg-blue-600 hover:bg-blue-500 text-white px-8 py-2 rounded-xl font-black uppercase text-[10px] tracking-widest shadow-lg flex items-center gap-2 transition-all active:scale-95">
                            {loading ? <RefreshCw className="animate-spin" size={18}/> : <Save size={18}/>} Lưu cấu hình
                        </button>
                    )}
                </div>
            </div>

            {/* --- SYSTEM DIALOG --- */}
            {dialog.isOpen && (
                <div className="fixed inset-0 z-[2000] bg-black/90 backdrop-blur-md flex items-center justify-center p-4 animate-in fade-in duration-200">
                    <div className="bg-gray-900 rounded-[2rem] w-full max-w-sm border border-gray-800 shadow-2xl overflow-hidden">
                        <div className="p-8 text-center flex flex-col items-center">
                            {dialog.type === 'success' && <div className="w-14 h-14 bg-emerald-500/20 text-emerald-500 rounded-full flex items-center justify-center mb-4"><CheckCircle2 size={28}/></div>}
                            {dialog.type === 'error' && <div className="w-14 h-14 bg-red-500/20 text-red-500 rounded-full flex items-center justify-center mb-4"><AlertTriangle size={28}/></div>}
                            {dialog.type === 'alert' && <div className="w-14 h-14 bg-blue-500/20 text-blue-500 rounded-full flex items-center justify-center mb-4"><Info size={28}/></div>}

                            <h3 className="text-lg font-black text-white uppercase tracking-tight mb-2">{dialog.title}</h3>
                            <p className="text-gray-400 text-xs leading-relaxed mb-6">{dialog.message}</p>

                            <button onClick={() => setDialog({ ...dialog, isOpen: false })} className="w-full py-3 bg-blue-600 hover:bg-blue-500 text-white rounded-xl font-black text-[10px] uppercase tracking-widest shadow-lg shadow-blue-900/20 transition-all active:scale-95">OK</button>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

export default SystemSettingsManager;

import React, { useState, useEffect, useRef } from 'react';
import { adminService } from '../../services/mockBackend';
import { SystemSetting } from '../../types';
// Added missing 'Check' icon to the lucide-react imports
import { Settings, Save, FileText, DatabaseBackup, Download, UploadCloud, RefreshCw, AlertTriangle, Image as ImageIcon, Trash2, Map as MapIcon, Shield, CheckCircle2, X, Info, Table, CheckSquare, Square, Check } from 'lucide-react';

const SystemSettingsManager: React.FC = () => {
    const [settings, setSettings] = useState<SystemSetting[]>([]);
    const [subTab, setSubTab] = useState<'GENERAL' | 'PDF' | 'MAP' | 'BACKUP'>('GENERAL');
    const [loading, setLoading] = useState(false);
    const [serverInfo, setServerInfo] = useState<any>(null);
    const backupInputRef = useRef<HTMLInputElement>(null);

    // Backup States
    const [backupTables, setBackupTables] = useState<{system: string[], spatial: string[]}>({ system: [], spatial: [] });
    const [selectedTables, setSelectedTables] = useState<string[]>([]);

    // System Dialog State
    const [dialog, setDialog] = useState<{
        isOpen: boolean;
        type: 'alert' | 'success' | 'error';
        title: string;
        message: string;
    }>({ isOpen: false, type: 'alert', title: '', message: '' });

    const showDialog = (type: any, title: string, message: string) => {
        setDialog({ isOpen: true, type, title, message });
    };

    useEffect(() => { loadData(); }, []);

    useEffect(() => {
        if (subTab === 'BACKUP') {
            loadBackupTables();
        }
    }, [subTab]);

    const loadData = async () => {
        setLoading(true);
        try {
            const [data, info] = await Promise.all([
                adminService.getSettings(),
                adminService.getServerInfo().catch(() => null)
            ]);
            setSettings(data);
            setServerInfo(info);
        } catch (e) { 
            console.error(e); 
        } finally {
            setLoading(false);
        }
    };

    const loadBackupTables = async () => {
        setLoading(true);
        try {
            const tables = await adminService.getBackupTables();
            setBackupTables(tables);
            // Mặc định chọn tất cả bảng hệ thống
            setSelectedTables([...tables.system, ...tables.spatial]);
        } catch (e) {
            console.error(e);
        } finally {
            setLoading(false);
        }
    };

    const toggleTableSelection = (tableName: string) => {
        setSelectedTables(prev => 
            prev.includes(tableName) 
            ? prev.filter(t => t !== tableName) 
            : [...prev, tableName]
        );
    };

    const handleSelectAll = (selectAll: boolean) => {
        if (selectAll) {
            setSelectedTables([...backupTables.system, ...backupTables.spatial]);
        } else {
            setSelectedTables([]);
        }
    };

    const handleSave = async () => {
        setLoading(true);
        try {
            await adminService.saveSettings(settings);
            showDialog('success', 'Đã lưu', "Hệ thống đã ghi nhận các thay đổi cấu hình mới.");
        } catch (e: any) {
            showDialog('error', 'Lỗi lưu trữ', e.message);
        } finally { setLoading(false); }
    };

    const handleStartBackup = async () => {
        if (selectedTables.length === 0) {
            showDialog('error', 'Lỗi', 'Vui lòng chọn ít nhất một bảng để sao lưu.');
            return;
        }

        setLoading(true);
        try {
            await adminService.createBackup(selectedTables);
            showDialog('success', 'Thành công', 'File SQL đã được tạo và đang tải xuống.');
        } catch (e: any) {
            showDialog('error', 'Lỗi Backup', e.message);
        } finally {
            setLoading(false);
        }
    };

    const handleFileChange = (key: string, e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (!file) return;

        if (file.size > 2 * 1024 * 1024) {
            showDialog('error', 'File quá lớn', "Vui lòng chọn ảnh dưới 2MB để đảm bảo hiệu năng tải trang.");
            return;
        }

        const reader = new FileReader();
        reader.onloadend = () => {
            const base64 = reader.result as string;
            setSettings(prev => prev.map(s => s.key === key ? { ...s, value: base64 } : s));
        };
        reader.readAsDataURL(file);
    };

    const renderSettingInput = (setting: SystemSetting) => {
        if (setting.type === 'image' || ['site_logo', 'site_favicon'].includes(setting.key)) {
            const isFavicon = setting.key === 'site_favicon';
            return (
                <div className="space-y-3">
                    {setting.value && (
                        <div className={`relative ${isFavicon ? 'w-16 h-16' : 'w-32 h-32'} bg-gray-900 rounded border border-gray-700 overflow-hidden group`}>
                            <img src={setting.value} alt={setting.key} className="w-full h-full object-contain p-1" />
                            <button 
                                onClick={() => setSettings(prev => prev.map(s => s.key === setting.key ? {...s, value: ''} : s))}
                                className="absolute inset-0 bg-black/50 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity"
                            >
                                <Trash2 className="text-red-400" size={isFavicon ? 14 : 20} />
                            </button>
                        </div>
                    )}
                    <label className="flex items-center gap-2 px-4 py-2 bg-gray-700 hover:bg-gray-600 rounded cursor-pointer w-fit text-sm transition-colors border border-gray-600">
                        <ImageIcon size={16} />
                        <span>{setting.value ? "Thay đổi" : "Tải lên"}</span>
                        <input type="file" accept="image/*" className="hidden" onChange={e => handleFileChange(setting.key, e)} />
                    </label>
                </div>
            );
        }

        if (setting.type === 'boolean') {
            const isTrue = setting.value === 'true';
            return (
                <div className="flex items-center gap-3">
                    <button 
                        onClick={() => setSettings(prev => prev.map(s => s.key === setting.key ? {...s, value: isTrue ? 'false' : 'true'} : s))}
                        className={`relative inline-flex h-6 w-11 items-center rounded-full transition-colors ${isTrue ? 'bg-blue-600' : 'bg-gray-700'}`}
                    >
                        <span className={`inline-block h-4 w-4 transform rounded-full bg-white transition-transform ${isTrue ? 'translate-x-6' : 'translate-x-1'}`} />
                    </button>
                    <span className="text-sm text-gray-400 font-bold uppercase tracking-widest">{isTrue ? "ĐANG BẬT" : "ĐANG TẮT"}</span>
                </div>
            );
        }

        return (
            <input 
                className="w-full bg-gray-900 border border-gray-600 rounded p-2.5 text-white focus:border-blue-500 outline-none font-medium" 
                value={setting.value} 
                type={setting.type === 'number' ? 'number' : 'text'}
                step={setting.type === 'number' ? 'any' : undefined}
                onChange={e => setSettings(prev => prev.map(item => item.key === setting.key ? {...item, value: e.target.value} : item))}
            />
        );
    };

    const isAllSelected = selectedTables.length === (backupTables.system.length + backupTables.spatial.length);

    return (
        <div className="p-8 max-w-5xl mx-auto space-y-6 text-white relative">
            <div className="flex gap-2 border-b border-gray-700 pb-2 overflow-x-auto no-scrollbar">
                <button onClick={() => setSubTab('GENERAL')} className={`px-4 py-2 text-sm font-bold whitespace-nowrap border-b-2 transition-all flex items-center gap-2 ${subTab === 'GENERAL' ? 'text-blue-400 border-blue-400' : 'text-gray-500 border-transparent'}`}><Settings size={16}/> Web & Bảo mật</button>
                <button onClick={() => setSubTab('MAP')} className={`px-4 py-2 text-sm font-bold whitespace-nowrap border-b-2 transition-all flex items-center gap-2 ${subTab === 'MAP' ? 'text-cyan-400 border-cyan-400' : 'text-gray-500 border-transparent'}`}><MapIcon size={16}/> Bản đồ</button>
                <button onClick={() => setSubTab('PDF')} className={`px-4 py-2 text-sm font-bold whitespace-nowrap border-b-2 transition-all flex items-center gap-2 ${subTab === 'PDF' ? 'text-orange-400 border-orange-400' : 'text-gray-500 border-transparent'}`}><FileText size={16}/> Mẫu trích lục</button>
                <button onClick={() => setSubTab('BACKUP')} className={`px-4 py-2 text-sm font-bold whitespace-nowrap border-b-2 transition-all flex items-center gap-2 ${subTab === 'BACKUP' ? 'text-green-400 border-green-400' : 'text-gray-500 border-transparent'}`}><DatabaseBackup size={16}/> Hệ thống</button>
            </div>

            <div className="bg-gray-800 rounded-lg p-6 border border-gray-700 shadow-xl min-h-[400px]">
                {subTab === 'GENERAL' && (
                    <div className="space-y-6 animate-in fade-in duration-300">
                        {settings.filter(s => ['system_name', 'site_logo', 'site_favicon', 'maintenance_mode', 'allow_registration'].includes(s.key)).map(s => (
                            <div key={s.key} className="grid grid-cols-1 md:grid-cols-3 gap-4 border-b border-gray-700/50 pb-6 last:border-0 last:pb-0">
                                <div className="col-span-1">
                                    <label className="text-sm font-bold text-gray-200 block mb-1">{s.label || s.key.replace(/_/g, ' ').toUpperCase()}</label>
                                    <span className="text-xs text-gray-500 italic">{s.description}</span>
                                </div>
                                <div className="col-span-2">
                                    {renderSettingInput(s)}
                                </div>
                            </div>
                        ))}
                    </div>
                )}

                {subTab === 'MAP' && (
                    <div className="space-y-6 animate-in fade-in duration-300">
                        <div className="p-4 bg-blue-900/10 border border-blue-800/30 rounded flex gap-3 items-center mb-4">
                            <MapIcon className="text-blue-400" size={24}/>
                            <p className="text-xs text-blue-300 italic">Thiết lập tọa độ trung tâm và mức zoom khi người dùng vừa truy cập bản đồ.</p>
                        </div>
                        {settings.filter(s => s.key.startsWith('map_') || s.key === 'default_zoom').map(s => (
                            <div key={s.key} className="grid grid-cols-1 md:grid-cols-3 gap-4 border-b border-gray-700/50 pb-6 last:border-0 last:pb-0">
                                <div className="col-span-1">
                                    <label className="text-sm font-bold text-gray-200 block mb-1">{s.label}</label>
                                    <span className="text-[10px] text-gray-500 font-mono">{s.key}</span>
                                </div>
                                <div className="col-span-2">
                                    {renderSettingInput(s)}
                                </div>
                            </div>
                        ))}
                    </div>
                )}

                {subTab === 'PDF' && (
                    <div className="space-y-6 animate-in fade-in duration-300">
                        {settings.filter(s => s.key.startsWith('pdf_') || s.key === 'footer_text').map(s => (
                            <div key={s.key} className="grid grid-cols-1 md:grid-cols-3 gap-4 border-b border-gray-700/50 pb-6 last:border-0 last:pb-0">
                                <div className="col-span-1">
                                    <label className="text-sm font-bold text-gray-200 block mb-1">{s.label || s.description}</label>
                                    <span className="text-xs text-gray-500 italic">{s.description}</span>
                                </div>
                                <div className="col-span-2">
                                    {renderSettingInput(s)}
                                </div>
                            </div>
                        ))}
                    </div>
                )}

                {subTab === 'BACKUP' && (
                    <div className="space-y-8 animate-in fade-in duration-300">
                        <div className="bg-gray-900/50 p-4 rounded border border-gray-700">
                            <h4 className="text-xs font-bold text-gray-500 uppercase mb-4 tracking-wider flex items-center gap-2">
                                <Shield size={14}/> Sức khỏe Máy chủ
                            </h4>
                            {serverInfo ? (
                                <div className="grid grid-cols-2 md:grid-cols-4 gap-4 text-xs">
                                    <div className="p-3 bg-gray-800 rounded border border-gray-700">
                                        <span className="text-gray-500 block mb-1">Hệ điều hành</span>
                                        <span className="font-bold text-blue-400">{serverInfo.osType}</span>
                                    </div>
                                    <div className="p-3 bg-gray-800 rounded border border-gray-700">
                                        <span className="text-gray-500 block mb-1">Thời gian chạy</span>
                                        <span className="font-bold text-green-400">{Math.floor(serverInfo.uptime / 3600)} giờ</span>
                                    </div>
                                    <div className="p-3 bg-gray-800 rounded border border-gray-700">
                                        <span className="text-gray-500 block mb-1">RAM Trống</span>
                                        <span className="font-bold text-yellow-400">{(serverInfo.freeMem / 1024 / 1024 / 1024).toFixed(2)} GB</span>
                                    </div>
                                    <div className="p-3 bg-gray-800 rounded border border-gray-700">
                                        <span className="text-gray-500 block mb-1">CPU Load</span>
                                        <span className="font-bold text-purple-400">{serverInfo.cpuUsage}%</span>
                                    </div>
                                </div>
                            ) : <p className="text-gray-500 italic">Đang tải thông tin máy chủ...</p>}
                        </div>

                        <div className="bg-gray-950/40 rounded-2xl border border-gray-700 p-6 space-y-6">
                            <div className="flex justify-between items-center border-b border-gray-700 pb-4">
                                <div className="flex items-center gap-3">
                                    <DatabaseBackup className="text-green-500" size={24} />
                                    <div>
                                        <h4 className="font-bold text-lg uppercase tracking-tight">Sao lưu SQL động</h4>
                                        <p className="text-xs text-gray-500 font-bold uppercase tracking-widest">Chọn các bảng cần kết xuất dữ liệu</p>
                                    </div>
                                </div>
                                <button 
                                    onClick={() => handleSelectAll(!isAllSelected)}
                                    className="text-xs font-black uppercase text-blue-400 hover:text-blue-300 flex items-center gap-2 transition-all"
                                >
                                    {isAllSelected ? <CheckSquare size={16}/> : <Square size={16}/>}
                                    {isAllSelected ? "Bỏ chọn tất cả" : "Chọn tất cả"}
                                </button>
                            </div>

                            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                                <div className="space-y-4">
                                    <h5 className="text-[10px] font-black text-gray-400 uppercase tracking-widest flex items-center gap-2">
                                        <Settings size={12}/> Bảng hệ thống ({backupTables.system.length})
                                    </h5>
                                    <div className="space-y-1 max-h-60 overflow-y-auto custom-scrollbar pr-2">
                                        {backupTables.system.map(table => (
                                            <div key={table} onClick={() => toggleTableSelection(table)} className="flex items-center gap-3 p-3 bg-gray-900/50 hover:bg-gray-800 rounded-xl cursor-pointer border border-gray-800 transition-all group">
                                                <div className={`w-5 h-5 rounded flex items-center justify-center border ${selectedTables.includes(table) ? 'bg-green-600 border-green-600' : 'border-gray-600'}`}>
                                                    {selectedTables.includes(table) && <Check size={14}/>}
                                                </div>
                                                <span className="text-xs font-mono text-gray-300 group-hover:text-white">{table}</span>
                                            </div>
                                        ))}
                                    </div>
                                </div>

                                <div className="space-y-4">
                                    <h5 className="text-[10px] font-black text-gray-400 uppercase tracking-widest flex items-center gap-2">
                                        <Table size={12}/> Bảng dữ liệu không gian ({backupTables.spatial.length})
                                    </h5>
                                    <div className="space-y-1 max-h-60 overflow-y-auto custom-scrollbar pr-2">
                                        {backupTables.spatial.length === 0 ? (
                                            <p className="text-xs text-gray-600 italic p-4">Không có bảng dữ liệu GIS nào được đăng ký.</p>
                                        ) : backupTables.spatial.map(table => (
                                            <div key={table} onClick={() => toggleTableSelection(table)} className="flex items-center gap-3 p-3 bg-gray-900/50 hover:bg-gray-800 rounded-xl cursor-pointer border border-gray-800 transition-all group">
                                                <div className={`w-5 h-5 rounded flex items-center justify-center border ${selectedTables.includes(table) ? 'bg-blue-600 border-blue-600' : 'border-gray-600'}`}>
                                                    {selectedTables.includes(table) && <Check size={14}/>}
                                                </div>
                                                <span className="text-xs font-mono text-gray-300 group-hover:text-white">{table}</span>
                                            </div>
                                        ))}
                                    </div>
                                </div>
                            </div>

                            <div className="pt-6 border-t border-gray-700 flex justify-between items-center">
                                <div className="text-xs text-gray-500 font-bold uppercase tracking-widest">
                                    Đã chọn: <span className="text-white">{selectedTables.length}</span> bảng
                                </div>
                                <button 
                                    onClick={handleStartBackup} 
                                    disabled={loading || selectedTables.length === 0} 
                                    className="bg-blue-600 hover:bg-blue-500 text-white px-8 py-3 rounded-2xl font-black uppercase text-xs tracking-widest shadow-xl shadow-blue-900/30 flex items-center gap-2 transition-all active:scale-95 disabled:opacity-30"
                                >
                                    {loading ? <RefreshCw className="animate-spin" size={16}/> : <Download size={16}/>} 
                                    TẢI XUỐNG BẢN SAO LƯU SQL
                                </button>
                            </div>
                        </div>

                        <div className="p-6 bg-orange-900/10 border border-orange-800/50 rounded-2xl flex flex-col gap-4">
                            <div className="flex items-center gap-3 text-orange-400">
                                <UploadCloud size={24}/>
                                <div>
                                    <h4 className="font-bold uppercase">Phục hồi Dữ liệu</h4>
                                    <p className="text-[10px] font-bold uppercase tracking-widest opacity-50">Yêu cầu quyền Super Admin</p>
                                </div>
                            </div>
                            <input type="file" accept=".sql" className="hidden" ref={backupInputRef} onChange={e => { const file = e.target.files?.[0]; if(file) { setLoading(true); adminService.restoreDatabase(file).then(()=>showDialog('success', 'Phục hồi', 'Hệ thống đã nạp lại dữ liệu thành công.')).catch(err=>showDialog('error', 'Lỗi phục hồi', err.message)).finally(()=>setLoading(false)); }}} />
                            <button onClick={() => backupInputRef.current?.click()} disabled={loading} className="bg-orange-600 hover:bg-orange-500 text-white py-3 rounded-2xl font-black uppercase text-xs tracking-widest flex items-center justify-center gap-2 transition-all active:scale-95">
                                {loading ? <RefreshCw className="animate-spin" size={16}/> : <ImageIcon size={16}/>} Chọn file .sql để phục hồi
                            </button>
                        </div>
                    </div>
                )}

                <div className="mt-8 flex justify-end gap-3 pt-6 border-t border-gray-700">
                    <button onClick={loadData} className="px-4 py-2 text-gray-400 hover:text-white font-bold uppercase text-[10px] tracking-widest">Làm mới</button>
                    {subTab !== 'BACKUP' && (
                        <button onClick={handleSave} disabled={loading} className="bg-blue-600 hover:bg-blue-500 text-white px-8 py-2 rounded-xl font-black uppercase text-[10px] tracking-widest shadow-lg flex items-center gap-2 transition-all active:scale-95">
                            {loading ? <RefreshCw className="animate-spin" size={18}/> : <Save size={18}/>} Lưu cấu hình
                        </button>
                    )}
                </div>
            </div>

            {/* --- SYSTEM DIALOG --- */}
            {dialog.isOpen && (
                <div className="fixed inset-0 z-[2000] bg-black/90 backdrop-blur-md flex items-center justify-center p-4 animate-in fade-in duration-200">
                    <div className="bg-gray-900 rounded-[2rem] w-full max-w-sm border border-gray-800 shadow-2xl overflow-hidden">
                        <div className="p-8 text-center flex flex-col items-center">
                            {dialog.type === 'success' && <div className="w-14 h-14 bg-emerald-500/20 text-emerald-500 rounded-full flex items-center justify-center mb-4"><CheckCircle2 size={28}/></div>}
                            {dialog.type === 'error' && <div className="w-14 h-14 bg-red-500/20 text-red-500 rounded-full flex items-center justify-center mb-4"><AlertTriangle size={28}/></div>}
                            {dialog.type === 'alert' && <div className="w-14 h-14 bg-blue-500/20 text-blue-500 rounded-full flex items-center justify-center mb-4"><Info size={28}/></div>}

                            <h3 className="text-lg font-black text-white uppercase tracking-tight mb-2">{dialog.title}</h3>
                            <p className="text-gray-400 text-xs leading-relaxed mb-6">{dialog.message}</p>

                            <button onClick={() => setDialog({ ...dialog, isOpen: false })} className="w-full py-3 bg-blue-600 hover:bg-blue-500 text-white rounded-xl font-black text-[10px] uppercase tracking-widest shadow-lg shadow-blue-900/20 transition-all active:scale-95">OK</button>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

export default SystemSettingsManager;

export enum UserRole {
  ADMIN = 'ADMIN',
  EDITOR = 'EDITOR',
  VIEWER = 'VIEWER'
}

export interface Message {
    id: number;
    sender_id: string;
    receiver_id: string;
    content: string;
    timestamp: string;
    is_read: boolean;
    sender_name?: string;
    receiver_name?: string;
    sender_avatar?: string;
}

export interface SystemNotification {
    id: number;
    title: string;
    content: string;
    type: 'INFO' | 'WARNING' | 'DANGER' | 'SUCCESS';
    target_role: string; // 'ALL', 'ADMIN', 'EDITOR', 'VIEWER'
    is_active: boolean;
    created_at: string;
    sender_name?: string;
}

export interface MenuItem {
    id: string;          // Mã định danh duy nhất
    label: string;       // Tên hiển thị
    icon: string;        // Tên icon từ Lucide
    roles: string[];     // Quyền truy cập
    order_index: number; // Thứ tự sắp xếp
    is_active: boolean;  // Trạng thái bật/tắt
    type?: 'INTERNAL' | 'EXTERNAL'; // Loại liên kết: INTERNAL (Page ID) hoặc EXTERNAL (URL)
    url?: string;        // Địa chỉ URL nếu là EXTERNAL
}

export interface Branch {
  id: string;
  name: string;
  code: string;
  address: string;
  contactEmail: string;
}

export interface User {
  id: string;
  email: string;
  name: string;
  role: UserRole;
  branchId: string;
  is_verified?: boolean; 
  can_chat?: boolean; // Mới: Quyền nhắn tin nội bộ
  avatar?: string; // Added field for Profile Picture (Base64 or URL)
}

export interface LandParcel {
  id: string;
  gid?: any;
  geometry: any;
  properties: {
    ownerName: string;
    landType: string;
    area: number;
    pricePerM2: number;
    totalValue: number;
    planningStatus: 'Safe' | 'Planning' | 'Disputed';
    branchId: string;
    updatedBy?: string;
    updatedAt?: string;
    [key: string]: any;
  };
}

export interface DashboardStats {
  totalParcels: number;
  totalArea: number;
  totalValue: number;
  parcelsByType: { name: string; value: number }[];
  valueByBranch: { name: string; value: number }[];
}

export interface SystemLog {
  id: string;
  userId: string;
  userName: string;
  action: string;
  details: string;
  timestamp: string;
  branchId: string;
}

export interface LandPriceConfig {
  landType: string;
  basePrice: number;
  description: string;
}

export interface AuthResponse {
  token: string;
  user: User;
}

export interface WMSLayerConfig {
    id: string;
    name: string;
    url: string;
    layers: string;
    visible: boolean;
    opacity?: number;
    type?: 'WMS' | 'XYZ'; // Mới: Hỗ trợ nhiều loại nguồn dữ liệu
}

export interface BasemapConfig {
    id: string;
    name: string;
    url: string; // URL XYZ template
    type: 'XYZ' | 'OSM' | 'GOOGLE';
    isDefault: boolean;
    visible: boolean;
}

export interface SystemSetting {
    key: string;
    value: string;
    label?: string;
    description?: string;
    type: 'text' | 'number' | 'boolean' | 'image';
}

export interface PermissionDefinition {
    code: string;
    name: string;
    group: 'MAP' | 'DATA' | 'SYSTEM' | 'REPORT';
}

export interface RoleConfig {
    role: UserRole;
    permissions: string[];
}

import React, { useEffect, useRef, useState, useCallback } from 'react';
import { User, LandParcel, WMSLayerConfig, BasemapConfig } from '../types';
import { gisService, API_URL } from '../services/mockBackend';
import { Loader2, Crosshair, Map as MapIcon, Layers as LayersIcon, Printer, Plus, Minus, Compass, AlertCircle, RefreshCw, Zap, Search, Fingerprint, MousePointer2, Navigation2, ArrowRight, MapPin } from 'lucide-react';
import proj4 from "proj4";
import { register } from 'ol/proj/proj4';
import { jsPDF } from 'jspdf';
import html2canvas from 'html2canvas';

// Components
import ParcelPopup from '../components/map/ParcelPopup';
import SearchPanel from '../components/map/SearchPanel';
import LayerControl from '../components/map/LayerControl';
import PrintTemplate from '../components/map/PrintTemplate';
import MeasureTools from '../components/map/MeasureTools';

// OpenLayers
import Map from 'ol/Map';
import View from 'ol/View';
import Overlay from 'ol/Overlay';
import Feature from 'ol/Feature';
import { Tile as TileLayer, Vector as VectorLayer, Group as LayerGroup } from 'ol/layer';
import { OSM, TileWMS, Vector as VectorSource, XYZ } from 'ol/source';
import * as proj from 'ol/proj';
import * as style from 'ol/style';
import { Point, LineString, Polygon, Circle as GeomCircle } from 'ol/geom';
import GeoJSON from 'ol/format/GeoJSON';
import { defaults as defaultControls } from 'ol/control/defaults';
import Collection from 'ol/Collection';
import { isEmpty as isExtentEmpty, getCenter as getExtentCenter } from 'ol/extent';
import { Coordinate } from 'ol/coordinate';
import Draw from 'ol/interaction/Draw';
import { getArea, getLength } from 'ol/sphere';
import { unByKey } from 'ol/Observable';

// SỬ DỤNG THAM SỐ 3-PARAM CHO BÌNH DƯƠNG (VN2000 KTT 105.75 Múi 3) ĐỂ KHỚP VỚI WEB MERCATOR HƠN
proj4.defs("EPSG:9210", "+proj=tmerc +lat_0=0 +lon_0=105.75 +k=0.9999 +x_0=500000 +y_0=0 +ellps=WGS84 +towgs84=-191.904,-39.303,-111.450,0,0,0,0 +units=m +no_defs");
register(proj4);

const MapPage: React.FC<{ user: User | null; systemSettings?: Record<string, string> }> = ({ user, systemSettings }) => {
    const mapElement = useRef<HTMLDivElement>(null);
    const popupElement = useRef<HTMLDivElement>(null);
    const mapInstance = useRef<Map | null>(null);

    const highlightLayer = useRef<VectorLayer<VectorSource> | null>(null);
    const locationLayer = useRef<VectorLayer<VectorSource> | null>(null);
    const measureSource = useRef<VectorSource>(new VectorSource());
    const wmsLayerGroup = useRef<LayerGroup | null>(null);
    const baseLayerRef = useRef<TileLayer<any> | null>(null);
    const overlayInstance = useRef<Overlay | null>(null);

    const [availableLayers, setAvailableLayers] = useState<WMSLayerConfig[]>([]);
    const [visibleLayerIds, setVisibleLayerIds] = useState<string[]>([]);
    const [activeLayerId, setActiveLayerId] = useState<string | null>(null);

    const [basemaps, setBasemaps] = useState<BasemapConfig[]>([]);
    const [activeBasemapId, setActiveBasemapId] = useState<string>('');

    const [spatialTables, setSpatialTables] = useState<any[]>([]);
    const [isSearchOpen, setIsSearchOpen] = useState(false);
    const [isLayerMenuOpen, setIsLayerMenuOpen] = useState(false);
    const [selectedParcel, setSelectedParcel] = useState<LandParcel | null>(null);
    const [isInitialLoading, setIsInitialLoading] = useState(true);
    const [isQuerying, setIsQuerying] = useState(false);
    const [isLocating, setIsLocating] = useState(false);
    const [isPrinting, setIsPrinting] = useState(false);
    const [printingParcel, setPrintingParcel] = useState<LandParcel | null>(null);
    const [mapRotation, setMapRotation] = useState(0);
    const [mapZoom, setMapZoom] = useState(0);
    const [mouseCoord, setMouseCoord] = useState<Coordinate | null>(null);

    const [measureMode, setMeasureMode] = useState<'LineString' | 'Polygon' | null>(null);
    const drawInteraction = useRef<Draw | null>(null);

    const highlightStyle = new style.Style({
        stroke: new style.Stroke({ color: '#00ffff', width: 4 }),
        fill: new style.Fill({ color: 'rgba(0, 255, 255, 0.2)' }),
        image: new style.Circle({ radius: 8, fill: new style.Fill({ color: '#00ffff' }), stroke: new style.Stroke({color: '#ffffff', width: 2}) })
    });

    const locationStyle = (feature: any) => {
        const type = feature.get('type');
        if (type === 'accuracy') {
            return new style.Style({
                fill: new style.Fill({ color: 'rgba(59, 130, 246, 0.1)' }),
                stroke: new style.Stroke({ color: 'rgba(59, 130, 246, 0.3)', width: 1 })
            });
        }
        if (type === 'search_result') {
            return new style.Style({
                image: new style.Icon({
                    anchor: [0.5, 1],
                    src: 'https://raw.githubusercontent.com/lucide-react/lucide/main/icons/map-pin.svg', 
                    color: '#ef4444',
                    scale: 2
                }),
                text: new style.Text({
                    text: '📍',
                    scale: 2,
                    offsetY: -10
                })
            });
        }
        return new style.Style({
            image: new style.Circle({
                radius: 8,
                fill: new style.Fill({ color: '#3b82f6' }),
                stroke: new style.Stroke({ color: '#fff', width: 3 })
            })
        });
    };

    const measureStyle = new style.Style({
        fill: new style.Fill({ color: 'rgba(59, 130, 246, 0.2)' }),
        stroke: new style.Stroke({ color: '#3b82f6', lineDash: [10, 10], width: 3 }),
        image: new style.Circle({ radius: 5, stroke: new style.Stroke({ color: '#3b82f6', width: 2 }), fill: new style.Fill({ color: '#fff' }) })
    });

    const smartMapProperties = (props: any) => {
        const findVal = (keys: string[]) => {
            for (const k of keys) {
                if (props[k] !== undefined && props[k] !== null && props[k] !== '') return props[k];
                const lower = k.toLowerCase();
                if (props[lower] !== undefined && props[lower] !== null && props[lower] !== '') return props[lower];
            }
            return null;
        };
        return {
            ...props,
            so_to: findVal(['sodoto', 'so_to', 'shbando', 'sh_ban_do', 'tobando', 'tờ']),
            so_thua: findVal(['sothua', 'so_thua', 'shthua', 'sh_thua', 'thửa']),
            ownerName: findVal(['tenchu', 'ten_chu', 'ten_chu_sd', 'owner']),
            area: parseFloat(findVal(['dientich', 'dien_tich', 'area']) || 0),
            landType: findVal(['loaidat', 'kyhieumucd', 'mucdich']) || 'N/A',
            address: findVal(['diachi', 'dia_chi', 'dc']) || ''
        };
    };

    const formatLength = (line: LineString) => {
        const length = getLength(line);
        return length > 100 ? (length / 1000).toFixed(2) + ' km' : length.toFixed(2) + ' m';
    };

    const formatArea = (polygon: Polygon) => {
        const area = getArea(polygon);
        return area > 10000 ? (area / 10000).toFixed(2) + ' ha' : area.toFixed(2) + ' m²';
    };

    const handlePrint = async (parcel: LandParcel) => {
        setIsPrinting(true);
        setPrintingParcel(parcel);
        setTimeout(async () => {
            const element = document.getElementById('print-template');
            if (!element) { setIsPrinting(false); setPrintingParcel(null); return; }
            try {
                const canvas = await html2canvas(element, { scale: 2.5, useCORS: true, logging: false, backgroundColor: '#ffffff' });
                const pdf = new jsPDF('p', 'mm', 'a4');
                const pdfWidth = pdf.internal.pageSize.getWidth();
                const pdfHeight = pdf.internal.pageSize.getHeight();
                const imgWidth = pdfWidth;
                const imgHeight = (canvas.height * pdfWidth) / canvas.width;
                let heightLeft = imgHeight;
                let position = 0;
                const imgData = canvas.toDataURL('image/jpeg', 1.0);
                pdf.addImage(imgData, 'JPEG', 0, position, imgWidth, imgHeight);
                heightLeft -= pdfHeight;
                while (heightLeft > 0) {
                    position -= pdfHeight;
                    pdf.addPage();
                    pdf.addImage(imgData, 'JPEG', 0, position, imgWidth, imgHeight);
                    heightLeft -= pdfHeight;
                }
                pdf.save(`TrichLuc_To${parcel.properties.so_to}_Thua${parcel.properties.so_thua}.pdf`);
            } catch (error) { console.error("Print Error:", error); } finally { setIsPrinting(false); setPrintingParcel(null); }
        }, 1200);
    };

    const handleSelectResult = useCallback((parcel: LandParcel, fallbackCoord?: Coordinate) => {
        if (!mapInstance.current || !highlightLayer.current) return;
        const normalizedParcel = { ...parcel, properties: smartMapProperties(parcel.properties) };
        setSelectedParcel(normalizedParcel);
        const source = highlightLayer.current.getSource();
        source?.clear();
        let popupPos = fallbackCoord;
        if (parcel.geometry) {
            try {
                const format = new GeoJSON();
                let firstCoord: any = null;
                if (parcel.geometry.type === 'Polygon') firstCoord = parcel.geometry.coordinates[0][0];
                else if (parcel.geometry.type === 'MultiPolygon') firstCoord = parcel.geometry.coordinates[0][0][0];
                else if (parcel.geometry.type === 'Point') firstCoord = parcel.geometry.coordinates;

                let dataProj = 'EPSG:4326';
                if (firstCoord) {
                    const x = Math.abs(firstCoord[0]);
                    const y = Math.abs(firstCoord[1]);
                    if (x > 2000000 || y > 2000000) dataProj = 'EPSG:3857';
                    else if (x > 300000 && x < 900000) dataProj = 'EPSG:9210';
                }
                const geometry = format.readGeometry(parcel.geometry, { dataProjection: dataProj, featureProjection: 'EPSG:3857' });
                if (geometry) {
                    const feature = new Feature({ geometry });
                    source?.addFeature(feature);
                    const extent = geometry.getExtent();
                    if (extent && !isExtentEmpty(extent)) {
                        popupPos = getExtentCenter(extent);
                        mapInstance.current.getView().fit(extent, { padding: [120, 120, 120, 120], duration: 800, maxZoom: 21 });
                    }
                }
            } catch (err) {}
        }
        if (popupPos) overlayInstance.current?.setPosition(popupPos);
    }, []);

    const handleActivateLayer = async (id: string) => {
        setActiveLayerId(id);
        if (!visibleLayerIds.includes(id)) {
            setVisibleLayerIds(prev => [...prev, id]);
        }
        const layer = availableLayers.find(l => l.id === id);
        if (layer && layer.type !== 'XYZ') {
            const tableName = layer.layers.includes(':') ? layer.layers.split(':')[1] : layer.layers;
            try {
                const res = await fetch(`${API_URL}/api/data/${tableName}/extent`);
                if (res.ok) {
                    const bounds = await res.json();
                    if (bounds && bounds.xmin !== undefined) {
                        let sourceProj = 'EPSG:4326';
                        if (Math.abs(bounds.xmin) > 100000) sourceProj = 'EPSG:9210';
                        const extent = proj.transformExtent([bounds.xmin, bounds.ymin, bounds.xmax, bounds.ymax], sourceProj, 'EPSG:3857');
                        if (mapInstance.current) mapInstance.current.getView().fit(extent, { padding: [50, 50, 50, 50], duration: 1000, maxZoom: 19 });
                    }
                }
            } catch (e) { console.warn("Zoom Error: ", tableName); }
        }
    };

    const handleSearchCoordinate = (lat: number, lon: number) => {
        const coords = proj.fromLonLat([lon, lat]);
        if (locationLayer.current) {
            const source = locationLayer.current.getSource();
            source?.getFeatures().forEach(f => { if (f.get('type') === 'search_result') source.removeFeature(f); });
            const feature = new Feature({ geometry: new Point(coords) });
            feature.set('type', 'search_result');
            source?.addFeature(feature);
        }
        mapInstance.current?.getView().animate({ center: coords, zoom: 18, duration: 1000 });
    };

    const initData = async () => {
        try {
            const [layers, tables, maps] = await Promise.all([
                gisService.getLayers().catch(() => []), 
                gisService.getSpatialTables().catch(() => []),
                gisService.getBasemaps().catch(() => [])
            ]);

            // THÊM LỚP QUY HOẠCH TDM NHƯ YÊU CẦU
            const quyHoachXYZ: WMSLayerConfig = {
                id: 'qh-tdm-xyz',
                name: 'Quy hoạch Thủ Dầu Một',
                url: 'https://geo.gisvn.space/data/khsdd/tdm/a/{z}/{x}/{y}.png',
                layers: 'planning',
                visible: false,
                opacity: 0.8,
                type: 'XYZ' // Đánh dấu là loại XYZ
            };

            const combinedLayers = [quyHoachXYZ, ...layers];
            setAvailableLayers(combinedLayers);
            setVisibleLayerIds(combinedLayers.filter(l => l.visible).map(l => l.id));
            setSpatialTables(tables);
            setBasemaps(maps);
            const defMap = maps.find(m => m.isDefault) || maps[0];
            if (defMap) setActiveBasemapId(defMap.id);
            if (combinedLayers.length && !activeLayerId) setActiveLayerId(combinedLayers[0].id);
        } catch (e) { console.error(e); } finally { setIsInitialLoading(false); }
    };

    useEffect(() => {
        if (!mapElement.current || mapInstance.current) return;
        const map = new Map({
            target: mapElement.current,
            layers: [
                new TileLayer({ zIndex: 0 }),
                new LayerGroup({ zIndex: 10 }),
                new VectorLayer({ source: new VectorSource(), zIndex: 10000, style: highlightStyle }),
                new VectorLayer({ source: new VectorSource(), zIndex: 20000, style: locationStyle }),
                new VectorLayer({ source: measureSource.current, zIndex: 30000, style: measureStyle }),
            ],
            view: new View({ center: proj.fromLonLat([106.619, 11.284]), zoom: 13, minZoom: 5, maxZoom: 22 }),
            controls: defaultControls({ attribution: false })
        });
        const layers = map.getLayers().getArray();
        baseLayerRef.current = layers[0] as TileLayer<any>;
        wmsLayerGroup.current = layers[1] as LayerGroup;
        highlightLayer.current = layers[2] as VectorLayer<VectorSource>;
        locationLayer.current = layers[3] as VectorLayer<VectorSource>;
        overlayInstance.current = new Overlay({ element: popupElement.current!, autoPan: { animation: { duration: 250 } }, positioning: 'bottom-center' });
        map.addOverlay(overlayInstance.current);

        map.on('singleclick', async (evt) => {
            if (measureMode) return; 
            const view = map.getView();
            const layers = wmsLayerGroup.current?.getLayers().getArray() || [];
            if (layers.length === 0) return;

            // Chỉ hỗ trợ GetFeatureInfo cho các lớp WMS
            const targetConfig = availableLayers.find(l => l.id === activeLayerId);
            if (targetConfig?.type === 'XYZ') return;

            const targetLayer = (layers.find(l => l.get('layerId') === activeLayerId) || layers[layers.length - 1]) as TileLayer<any>;
            if (!targetLayer.getSource()?.getFeatureInfoUrl) return;

            const url = targetLayer.getSource().getFeatureInfoUrl(evt.coordinate, view.getResolution()!, view.getProjection(), { 'INFO_FORMAT': 'application/json', 'FEATURE_COUNT': 1 });
            if (url) {
                setIsQuerying(true);
                overlayInstance.current?.setPosition(undefined);
                setSelectedParcel(null);
                highlightLayer.current?.getSource()?.clear();
                try {
                    const res = await fetch(url);
                    const data = await res.json();
                    if (data.features?.length > 0) {
                        const f = data.features[0];
                        handleSelectResult({ id: f.id, gid: f.properties.gid || parseInt(f.id.split('.').pop()||'0'), geometry: f.geometry, properties: f.properties }, evt.coordinate);
                    }
                } catch (e) { console.error("Query failed", e); } finally { setIsQuerying(false); }
            }
        });
        map.on('pointermove', (evt) => { if (!evt.dragging) setMouseCoord(proj.toLonLat(evt.coordinate)); });
        map.getView().on('change:rotation', () => setMapRotation(map.getView().getRotation()));
        map.getView().on('change:resolution', () => setMapZoom(map.getView().getZoom() || 0));
        const resizeObserver = new ResizeObserver(() => map.updateSize());
        resizeObserver.observe(mapElement.current);
        mapInstance.current = map;
        initData();
        return () => resizeObserver.disconnect();
    }, [handleSelectResult, measureMode, activeLayerId]);

    useEffect(() => {
        if (!mapInstance.current || !measureMode) {
            if (drawInteraction.current) mapInstance.current?.removeInteraction(drawInteraction.current);
            return;
        }
        const map = mapInstance.current;
        drawInteraction.current = new Draw({ source: measureSource.current, type: measureMode, style: measureStyle });
        map.addInteraction(drawInteraction.current);
        let listener: any;
        drawInteraction.current.on('drawstart', (evt) => {
            const feature = evt.feature;
            const tooltipElement = document.createElement('div');
            tooltipElement.className = 'bg-black/80 text-white px-2 py-1 rounded text-[10px] font-bold shadow-xl backdrop-blur-sm border border-white/20 pointer-events-none whitespace-nowrap';
            const tooltip = new Overlay({ element: tooltipElement, offset: [0, -15], positioning: 'bottom-center', stopEvent: false, insertFirst: false });
            map.addOverlay(tooltip);
            listener = feature.getGeometry()?.on('change', (evt: any) => {
                const geom = evt.target;
                let output = '';
                let tooltipCoord: Coordinate | undefined;
                if (geom instanceof Polygon) { output = formatArea(geom); tooltipCoord = geom.getInteriorPoint().getCoordinates(); }
                else if (geom instanceof LineString) { output = formatLength(geom); tooltipCoord = geom.getLastCoordinate(); }
                tooltipElement.innerHTML = output;
                if (tooltipCoord) tooltip.setPosition(tooltipCoord);
            });
        });
        drawInteraction.current.on('drawend', () => { if (listener) unByKey(listener); setMeasureMode(null); });
        return () => { if (drawInteraction.current) map.removeInteraction(drawInteraction.current); };
    }, [measureMode]);

    const handleClearMeasure = () => {
        measureSource.current.clear();
        mapInstance.current?.getOverlays().getArray().filter(o => o !== overlayInstance.current).forEach(o => mapInstance.current?.removeOverlay(o));
    };

    const handleZoomIn = () => { const view = mapInstance.current?.getView(); if (view) view.animate({ zoom: (view.getZoom() || 0) + 1, duration: 250 }); };
    const handleZoomOut = () => { const view = mapInstance.current?.getView(); if (view) view.animate({ zoom: (view.getZoom() || 0) - 1, duration: 250 }); };
    const handleResetRotation = () => mapInstance.current?.getView().animate({ rotation: 0, duration: 500 });
    const handleLocate = () => {
        if (!navigator.geolocation) return alert("Không hỗ trợ định vị.");
        setIsLocating(true);
        navigator.geolocation.getCurrentPosition(
            (pos) => {
                const coords = proj.fromLonLat([pos.coords.longitude, pos.coords.latitude]);
                if (locationLayer.current) {
                    const source = locationLayer.current.getSource();
                    source?.getFeatures().forEach(f => { const type = f.get('type'); if (type === 'accuracy' || type === 'position') source.removeFeature(f); });
                    source?.addFeature(new Feature({ geometry: new GeomCircle(coords, pos.coords.accuracy) }).set('type', 'accuracy') as any);
                    source?.addFeature(new Feature({ geometry: new Point(coords) }).set('type', 'position') as any);
                }
                mapInstance.current?.getView().animate({ center: coords, zoom: Math.max(18, mapInstance.current.getView().getZoom() || 0), duration: 1000 });
                setIsLocating(false);
            },
            () => setIsLocating(false),
            { enableHighAccuracy: true, timeout: 15000, maximumAge: 0 }
        );
    };

    useEffect(() => {
        if (!baseLayerRef.current || !activeBasemapId || basemaps.length === 0) return;
        const config = basemaps.find(m => m.id === activeBasemapId);
        if (!config) return;
        let source;
        if (config.type === 'OSM') source = new OSM({ crossOrigin: 'anonymous' });
        else source = new XYZ({ url: config.url.startsWith('/') ? `${API_URL}${config.url}` : config.url, crossOrigin: 'anonymous' });
        baseLayerRef.current.setSource(source);
    }, [activeBasemapId, basemaps]);

    useEffect(() => {
        if (!wmsLayerGroup.current) return;
        const olLayers = availableLayers.filter(l => visibleLayerIds.includes(l.id)).map(config => {
            let source;
            if (config.type === 'XYZ') {
                source = new XYZ({ 
                    url: config.url, 
                    crossOrigin: 'anonymous' 
                });
            } else {
                source = new TileWMS({ 
                    url: `${API_URL}/api/proxy/forward?url=${encodeURIComponent(config.url)}`, 
                    params: { 'LAYERS': config.layers, 'TILED': true, 'TRANSPARENT': true, 'FORMAT': 'image/png' }, 
                    crossOrigin: 'anonymous' 
                });
            }

            const layer = new TileLayer({
                source: source,
                opacity: Number(config.opacity ?? 1),
                zIndex: activeLayerId === config.id ? 50 : 10
            });
            layer.set('layerId', config.id);
            return layer;
        });
        wmsLayerGroup.current.setLayers(new Collection(olLayers));
    }, [availableLayers, visibleLayerIds, activeLayerId]);

    return (
        <div className="relative w-full h-full bg-slate-950 flex flex-col min-h-0 overflow-hidden font-sans">
            {isInitialLoading && (
                <div className="absolute inset-0 z-[1000] bg-slate-900 flex flex-col items-center justify-center text-white gap-4">
                    <Loader2 className="animate-spin text-blue-500" size={48} />
                    <p className="font-bold tracking-widest text-sm uppercase animate-pulse">Đang nạp dữ liệu...</p>
                </div>
            )}

            <div className="absolute bottom-6 left-6 z-[400] flex flex-col gap-2 pointer-events-none">
                {mouseCoord && (
                    <div className="bg-slate-900/80 backdrop-blur-md border border-slate-700/50 px-3 py-1.5 rounded-xl shadow-2xl flex items-center gap-3 animate-in fade-in duration-300">
                        <div className="flex items-center gap-1.5 text-blue-400"><MousePointer2 size={12}/><span className="text-[9px] font-black uppercase tracking-[0.1em]">Tọa độ</span></div>
                        <div className="flex gap-4 font-mono text-[11px] font-bold text-gray-100">
                            <div className="flex items-baseline gap-1"><span className="text-gray-500 text-[9px]">X:</span><span>{mouseCoord[0].toFixed(6)}</span></div>
                            <div className="flex items-baseline gap-1"><span className="text-gray-500 text-[9px]">Y:</span><span>{mouseCoord[1].toFixed(6)}</span></div>
                        </div>
                    </div>
                )}
                <div className="w-fit bg-slate-900/80 backdrop-blur-md border border-slate-700/50 px-2.5 py-1 rounded-lg flex items-center gap-2">
                    <div className="w-1.5 h-1.5 rounded-full bg-green-500 animate-pulse"></div>
                    <span className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Zoom: <span className="text-white ml-1">{Math.round(mapZoom)}</span></span>
                </div>
            </div>

            <div className="absolute bottom-28 left-1/2 -translate-x-1/2 z-[400] flex flex-col gap-2 pointer-events-none items-center w-full max-w-sm px-4">
                {isQuerying && (
                    <div className="w-full bg-slate-900/80 backdrop-blur-2xl border border-cyan-500/40 p-1.5 rounded-2xl shadow-2xl animate-in slide-in-from-bottom-8">
                        <div className="flex items-center gap-3 px-4 py-2">
                            <Fingerprint size={18} className="text-cyan-400 animate-pulse" />
                            <div className="flex-1"><p className="text-[10px] font-black text-cyan-400 uppercase tracking-[0.2em]">Spatial Query</p><p className="text-[9px] text-gray-400 font-bold uppercase">Đang nhận dạng thửa đất...</p></div>
                        </div>
                    </div>
                )}
            </div>

            {isPrinting && (
                <div className="absolute inset-0 z-[2000] bg-black/70 backdrop-blur-md flex flex-col items-center justify-center text-white gap-4">
                    <Printer className="animate-bounce text-orange-500" size={64} />
                    <div className="text-center">
                        <p className="font-display font-bold text-xl uppercase tracking-tighter">Đang xuất trích lục đa trang</p>
                    </div>
                </div>
            )}

            <div ref={mapElement} className="flex-1 w-full relative" />
            <MeasureTools activeMode={measureMode} onModeChange={setMeasureMode} onClear={handleClearMeasure} />

            <div ref={popupElement} className="absolute bottom-0 left-0 pointer-events-none">
                {selectedParcel && (
                    <div className="pointer-events-auto">
                        <ParcelPopup parcel={selectedParcel} user={user} onClose={() => { overlayInstance.current?.setPosition(undefined); setSelectedParcel(null); highlightLayer.current?.getSource()?.clear(); }} onPrint={handlePrint} />
                    </div>
                )}
            </div>

            <div className="fixed -left-[4000px] top-0 opacity-0 pointer-events-none overflow-hidden">
                {printingParcel && <PrintTemplate parcel={printingParcel} user={user} systemSettings={systemSettings} />}
            </div>

            <div className="absolute bottom-6 right-6 z-[400] flex flex-col gap-3">
                {Math.abs(mapRotation) > 0.01 && (
                    <button onClick={handleResetRotation} className="p-3 bg-white rounded-full shadow-2xl text-orange-600 hover:bg-orange-50 transition-all"><Compass size={24} style={{ transform: `rotate(${-mapRotation}rad)` }}/></button>
                )}
                <div className="flex flex-col bg-white rounded-2xl shadow-2xl border border-gray-100 overflow-hidden">
                    <button onClick={handleZoomIn} className="p-3.5 text-gray-700 hover:bg-gray-50 border-b border-gray-100 transition-colors"><Plus size={20}/></button>
                    <button onClick={handleZoomOut} className="p-3.5 text-gray-700 hover:bg-gray-50 transition-colors"><Minus size={20}/></button>
                </div>
                <button onClick={handleLocate} className={`p-3.5 rounded-full shadow-2xl text-white transition-all ${isLocating ? 'bg-gray-400' : 'bg-blue-600 hover:bg-blue-700'}`}><Crosshair size={24} className={isLocating ? "animate-spin" : ""}/></button>
            </div>

            <SearchPanel 
                isOpen={isSearchOpen} 
                onToggle={() => setIsSearchOpen(!isSearchOpen)} 
                spatialTables={spatialTables} 
                onSelectResult={p => handleSelectResult(p)}
                onSearchCoordinate={handleSearchCoordinate}
            />
            <LayerControl isOpen={isLayerMenuOpen} onToggleMenu={() => setIsLayerMenuOpen(!isLayerMenuOpen)} basemaps={basemaps} activeBasemapId={activeBasemapId} onBaseLayerChange={setActiveBasemapId} availableLayers={availableLayers} visibleLayerIds={visibleLayerIds} activeLayerId={activeLayerId} onToggleWMS={id => setVisibleLayerIds(prev => prev.includes(id) ? prev.filter(x => x !== id) : [...prev, id])} onSetActiveWMS={handleActivateLayer} onOpacityChange={(id, opacity) => setAvailableLayers(prev => prev.map(l => l.id === id ? { ...l, opacity } : l))} />
        </div>
    );
};

export default MapPage;

import React, { useState, useEffect } from 'react';
import { adminService } from '../../services/mockBackend';
import { parcelApi } from '../../services/parcelApi';
import { WMSLayerConfig, BasemapConfig } from '../../types';
import { Layers, Database, Plus, Edit2, Trash2, X, Eye, EyeOff, Save, Table, Link2Off, RefreshCw, Map as MapIcon, CheckCircle2, Globe, AlertCircle, Check, ShieldAlert, Lock } from 'lucide-react';

interface LayerManagerProps {
    dbStatus: any;
}

const LayerManager: React.FC<LayerManagerProps> = ({ dbStatus }) => {
    const [wmsLayers, setWmsLayers] = useState<WMSLayerConfig[]>([]);
    const [basemaps, setBasemaps] = useState<BasemapConfig[]>([]);
    const [spatialTables, setSpatialTables] = useState<any[]>([]);
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState<string | null>(null);

    // Modal State
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [modalType, setModalType] = useState<'LAYER' | 'TABLE' | 'BASEMAP' | null>(null);
    const [formData, setFormData] = useState<any>({});
    const [isEditMode, setIsEditMode] = useState(false);

    // Custom Confirmation Dialog State
    const [confirmDialog, setConfirmDialog] = useState<{
        isOpen: boolean;
        title: string;
        message: string;
        actionType: 'UNLINK' | 'DROP_TABLE' | 'DELETE_WMS' | 'DELETE_BASEMAP';
        targetId: string;
        targetName: string;
        isDangerous?: boolean;
    }>({
        isOpen: false,
        title: '',
        message: '',
        actionType: 'UNLINK',
        targetId: '',
        targetName: ''
    });

    useEffect(() => { loadData(); }, []);

    const loadData = async () => {
        setLoading(true);
        setError(null);
        try {
            const [layers, tables, maps] = await Promise.all([
                adminService.getWmsLayers().catch(() => []),
                parcelApi.manageTables.getAll().catch(() => []),
                adminService.getBasemaps().catch(() => [])
            ]);
            setWmsLayers(layers || []);
            setSpatialTables(tables || []);
            setBasemaps(maps || []);
        } catch (e: any) {
            setError("Không thể tải toàn bộ dữ liệu cấu hình.");
        } finally { setLoading(false); }
    };

    const openModal = (type: 'LAYER' | 'TABLE' | 'BASEMAP', item?: any) => {
        setModalType(type);
        setIsEditMode(!!item);

        if (type === 'LAYER') {
            setFormData(item ? { ...item, type: item.type || 'WMS' } : { name: '', url: '', layers: '', visible: true, opacity: 1, type: 'WMS' });
        } else if (type === 'TABLE') {
            if (item) {
                setFormData({
                    tableName: item.table_name,
                    originalName: item.table_name, // Lưu tên gốc để xử lý rename
                    displayName: item.display_name || item.table_name,
                    description: item.description || ''
                });
            } else {
                setFormData({
                    tableName: '',
                    displayName: '',
                    description: '',
                    isExisting: false
                });
            }
        } else if (type === 'BASEMAP') {
            setFormData(item ? { ...item } : { name: '', url: '', type: 'XYZ', isDefault: false, visible: true });
        }
        setIsModalOpen(true);
    };

    const handleSave = async () => {
        try {
            setLoading(true);
            if (modalType === 'LAYER') {
                isEditMode ? await adminService.updateWmsLayer(formData) : await adminService.addWmsLayer(formData);
            } else if (modalType === 'BASEMAP') {
                isEditMode ? await adminService.updateBasemap(formData) : await adminService.addBasemap(formData);
            } else if (modalType === 'TABLE') {
                if (!formData.tableName || !formData.displayName) {
                    throw new Error("Vui lòng nhập đầy đủ Tên bảng vật lý và Tên hiển thị.");
                }

                if (isEditMode) {
                    // Nếu đang sửa: Gọi API rename để cập nhật thông tin trong registry (bao gồm cả tableName nếu user sửa)
                    // API này KHÔNG alter table vật lý
                    await parcelApi.manageTables.rename(formData.originalName, formData.tableName, formData.displayName, formData.description);
                } else {
                    // Khi thêm mới
                    if (formData.isExisting) {
                        await parcelApi.manageTables.link(formData.tableName, formData.displayName, formData.description);
                    } else {
                        await parcelApi.manageTables.create(formData.tableName, formData.displayName, formData.description);
                    }
                }
            }
            setIsModalOpen(false);
            await loadData();
        } catch (e: any) { 
            setError(e.message);
        } finally { setLoading(false); }
    };

    // Hàm nhanh để đổi trạng thái ẩn hiện ngay trên bảng (WMS)
    const toggleWmsVisibility = async (layer: WMSLayerConfig) => {
        try {
            setLoading(true);
            await adminService.updateWmsLayer({ ...layer, visible: !layer.visible });
            await loadData();
        } catch (e: any) {
            setError(e.message);
        } finally { setLoading(false); }
    };

    // TRIGGER CONFIRMATION
    const triggerConfirm = (type: typeof confirmDialog['actionType'], id: string, name: string) => {
        let title = '';
        let message = '';
        let isDangerous = false;

        switch(type) {
            case 'UNLINK':
                title = 'Hủy liên kết Registry';
                message = `Bạn có chắc chắn muốn hủy liên kết bảng "${name}"? Thao tác này chỉ xóa thông tin quản lý trong phần mềm, dữ liệu trong Database của bạn vẫn được giữ nguyên.`;
                break;
            case 'DROP_TABLE':
                title = 'XÓA VĨNH VIỄN BẢNG';
                message = `CẢNH BÁO NGUY HIỂM: Bạn đang yêu cầu xóa vĩnh viễn bảng "${name}" khỏi Database. Hành động này sẽ XÓA TOÀN BỘ DỮ LIỆU và không thể khôi phục.`;
                isDangerous = true;
                break;
            case 'DELETE_WMS':
                title = 'Xóa lớp chuyên đề';
                message = `Xóa cấu hình lớp bản đồ chuyên đề "${name}"?`;
                break;
            case 'DELETE_BASEMAP':
                title = 'Xóa bản đồ nền';
                message = `Xóa cấu hình bản đồ nền "${name}"?`;
                break;
        }

        setConfirmDialog({
            isOpen: true,
            title,
            message,
            actionType: type,
            targetId: id,
            targetName: name,
            isDangerous
        });
    };

    // EXECUTE CONFIRMED ACTION
    const executeAction = async () => {
        const { actionType, targetId } = confirmDialog;
        setConfirmDialog(prev => ({ ...prev, isOpen: false }));
        setLoading(true);

        try {
            switch(actionType) {
                case 'UNLINK':
                    await parcelApi.manageTables.unlink(targetId);
                    break;
                case 'DROP_TABLE':
                    await parcelApi.manageTables.delete(targetId);
                    break;
                case 'DELETE_WMS':
                    await adminService.deleteWmsLayer(targetId);
                    break;
                case 'DELETE_BASEMAP':
                    await adminService.deleteBasemap(targetId);
                    break;
            }
            await loadData();
        } catch (e: any) {
            setError("Lỗi thực thi: " + e.message);
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="p-8 space-y-10 pb-24 max-w-7xl mx-auto">
            {error && (
                <div className="bg-red-900/20 border border-red-800 text-red-400 p-4 rounded-lg flex items-center justify-between gap-3 animate-in slide-in-from-top-2">
                    <div className="flex items-center gap-3">
                        <AlertCircle size={20} />
                        <span className="text-sm font-medium">{error}</span>
                    </div>
                    <button onClick={() => setError(null)} className="hover:text-white transition-colors"><X size={16}/></button>
                </div>
            )}

            {/* 1. DATABASE STATUS */}
            <div className="bg-gray-800 rounded-lg border border-gray-700 p-6 shadow-xl">
                <div className="flex justify-between items-center mb-4">
                    <h3 className="text-lg font-bold flex items-center gap-2 text-white">
                        <Database className="text-blue-400" /> Kết nối Database PostGIS
                    </h3>
                    <button onClick={loadData} disabled={loading} className="text-xs text-blue-400 hover:text-blue-300 flex items-center gap-1 transition-colors disabled:opacity-50">
                        <RefreshCw size={12} className={loading ? "animate-spin" : ""} /> Làm mới dữ liệu
                    </button>
                </div>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4 text-sm font-mono text-gray-300 bg-gray-900 p-4 rounded border border-gray-700 shadow-inner">
                    <p><span className="text-gray-500">Trạng thái:</span> <span className="text-green-400 font-bold">ĐANG KẾT NỐI</span></p>
                    <p><span className="text-gray-500">Database:</span> <span className="text-blue-400">{dbStatus.dbName || 'dulieu_geogis'}</span></p>
                </div>
            </div>

            {/* 2. SPATIAL TABLES REGISTRY */}
            <div className="bg-gray-800 rounded-lg border border-gray-700 shadow-xl overflow-hidden">
                <div className="p-4 flex justify-between border-b border-gray-700 bg-gray-800/50">
                    <span className="font-semibold text-gray-100 flex items-center gap-2">
                        <Table size={18} className="text-green-400"/> Quản lý Bảng Dữ liệu (Registry)
                    </span>
                    <button onClick={() => openModal('TABLE')} className="bg-green-600 hover:bg-green-500 text-white px-4 py-1.5 rounded text-sm font-bold flex items-center gap-1 transition-all">
                        <Plus size={16}/> Thêm / Liên kết
                    </button>
                </div>
                <div className="overflow-x-auto">
                    <table className="w-full text-sm text-left">
                        <thead className="bg-gray-900 text-gray-400 uppercase text-[10px] tracking-widest font-black">
                            <tr><th className="p-4 w-1/4">Tên bảng (DB)</th><th className="p-4 w-1/4">Tên hiển thị</th><th className="p-4 w-1/3">Mô tả</th><th className="p-4 text-right">Quản trị</th></tr>
                        </thead>
                        <tbody className="divide-y divide-gray-700 text-gray-300">
                            {spatialTables.map(t => (
                                <tr key={t.table_name} className="hover:bg-gray-700/30 transition-colors">
                                    <td className="p-4 font-mono text-blue-300 text-xs">{t.table_name}</td>
                                    <td className="p-4 font-medium text-white">{t.display_name || t.table_name}</td>
                                    <td className="p-4 text-xs text-gray-500 truncate max-w-[200px]">{t.description || '--'}</td>
                                    <td className="p-4 flex justify-end gap-1">
                                        <button onClick={() => openModal('TABLE', t)} className="p-2 text-blue-400 hover:bg-blue-400/10 rounded"><Edit2 size={16}/></button>
                                        <button onClick={() => triggerConfirm('UNLINK', t.table_name, t.display_name || t.table_name)} className="p-2 text-orange-400 hover:bg-orange-400/10 rounded"><Link2Off size={16}/></button>
                                        <button onClick={() => triggerConfirm('DROP_TABLE', t.table_name, t.table_name)} className="p-2 text-red-500 hover:bg-red-500/10 rounded"><Trash2 size={16}/></button>
                                    </td>
                                </tr>
                            ))}
                        </tbody>
                    </table>
                </div>
            </div>

            {/* 3. WMS LAYERS SECTION */}
            <div className="bg-gray-800 rounded-lg border border-gray-700 shadow-xl overflow-hidden">
                <div className="p-4 flex justify-between border-b border-gray-700 bg-gray-800/50">
                    <span className="font-semibold text-gray-100 flex items-center gap-2">
                        <Globe size={18} className="text-cyan-400"/> Lớp bản đồ chuyên đề (WMS/XYZ)
                    </span>
                    <button onClick={() => openModal('LAYER')} className="bg-cyan-600 hover:bg-cyan-500 text-white px-4 py-1.5 rounded text-sm font-bold flex items-center gap-1 transition-all">
                        <Plus size={16}/> Thêm Lớp Dữ liệu
                    </button>
                </div>
                <div className="overflow-x-auto">
                    <table className="w-full text-sm text-left">
                        <thead className="bg-gray-900 text-gray-400 uppercase text-[10px] tracking-widest font-black">
                            <tr><th className="p-4">Tên hiển thị</th><th className="p-4">Nguồn</th><th className="p-4">Workspace/Layers</th><th className="p-4">Trạng thái</th><th className="p-4 text-right">Thao tác</th></tr>
                        </thead>
                        <tbody className="divide-y divide-gray-700 text-gray-300">
                            {wmsLayers.map(l => (
                                <tr key={l.id} className="hover:bg-gray-700/30 transition-colors">
                                    <td className="p-4 font-bold text-white">{l.name}</td>
                                    <td className="p-4">
                                        <span className={`px-2 py-0.5 rounded text-[9px] font-black uppercase border ${l.type === 'XYZ' ? 'bg-orange-900/30 text-orange-400 border-orange-800/40' : 'bg-cyan-900/30 text-cyan-400 border-cyan-800/40'}`}>
                                            {l.type || 'WMS'}
                                        </span>
                                    </td>
                                    <td className="p-4 font-mono text-xs text-gray-400 max-w-[200px] truncate">{l.layers}</td>
                                    <td className="p-4">
                                        <button onClick={() => toggleWmsVisibility(l)} className="flex items-center gap-2">
                                            {l.visible ? (
                                                <span className="flex items-center gap-1.5 text-green-400 text-[10px] uppercase font-black bg-green-900/20 px-2 py-1 rounded-full border border-green-800/40">
                                                    <Eye size={12}/> Đang hiện
                                                </span>
                                            ) : (
                                                <span className="flex items-center gap-1.5 text-gray-500 text-[10px] uppercase font-black bg-gray-900 px-2 py-1 rounded-full border border-gray-700">
                                                    <EyeOff size={12}/> Đang ẩn
                                                </span>
                                            )}
                                        </button>
                                    </td>
                                    <td className="p-4 flex justify-end gap-1">
                                        <button onClick={() => openModal('LAYER', l)} className="p-2 text-blue-400 hover:bg-blue-400/10 rounded transition-all"><Edit2 size={16}/></button>
                                        <button onClick={() => triggerConfirm('DELETE_WMS', l.id, l.name)} className="p-2 text-red-500 hover:bg-red-500/10 rounded transition-all"><Trash2 size={16}/></button>
                                    </td>
                                </tr>
                            ))}
                        </tbody>
                    </table>
                </div>
            </div>

            {/* 4. BASEMAPS SECTION */}
            <div className="bg-gray-800 rounded-lg border border-gray-700 shadow-xl overflow-hidden">
                <div className="p-4 flex justify-between border-b border-gray-700 bg-gray-800/50">
                    <span className="font-semibold text-gray-100 flex items-center gap-2">
                        <MapIcon size={18} className="text-orange-400"/> Quản lý Bản đồ nền (Basemaps)
                    </span>
                    <button onClick={() => openModal('BASEMAP')} className="bg-orange-600 hover:bg-orange-500 text-white px-4 py-1.5 rounded text-sm font-bold flex items-center gap-1 shadow-lg transition-all">
                        <Plus size={16}/> Thêm Bản đồ nền
                    </button>
                </div>
                <div className="overflow-x-auto">
                    <table className="w-full text-sm text-left">
                        <thead className="bg-gray-900 text-gray-400 uppercase text-[10px] tracking-widest font-black">
                            <tr><th className="p-4">Tên bản đồ</th><th className="p-4">Loại</th><th className="p-4">Mặc định</th><th className="p-4">Trạng thái</th><th className="p-4 text-right">Thao tác</th></tr>
                        </thead>
                        <tbody className="divide-y divide-gray-700 text-gray-300">
                            {basemaps.map(bm => (
                                <tr key={bm.id} className="hover:bg-gray-700/30 transition-colors">
                                    <td className="p-4 font-bold text-white">{bm.name}</td>
                                    <td className="p-4 text-xs font-mono text-gray-400">{bm.type}</td>
                                    <td className="p-4">
                                        {bm.isDefault ? (
                                            <span className="bg-orange-900/40 text-orange-400 text-[9px] px-2 py-0.5 rounded-full border border-orange-800 font-black uppercase">Mặc định</span>
                                        ) : '--'}
                                    </td>
                                    <td className="p-4">{bm.visible ? <span className="text-green-400 text-[10px] uppercase font-bold">Hiện</span> : <span className="text-gray-500 text-[10px] uppercase font-bold">Ẩn</span>}</td>
                                    <td className="p-4 flex justify-end gap-1">
                                        <button onClick={() => openModal('BASEMAP', bm)} className="p-2 text-blue-400 hover:bg-blue-400/10 rounded transition-all"><Edit2 size={16}/></button>
                                        <button onClick={() => triggerConfirm('DELETE_BASEMAP', bm.id, bm.name)} className="p-2 text-red-500 hover:bg-red-500/10 rounded transition-all"><Trash2 size={16}/></button>
                                    </td>
                                </tr>
                            ))}
                        </tbody>
                    </table>
                </div>
            </div>

            {/* --- CUSTOM CONFIRMATION DIALOG MODAL --- */}
            {confirmDialog.isOpen && (
                <div className="fixed inset-0 z-[600] bg-black/90 backdrop-blur-md flex items-center justify-center p-4 animate-in fade-in duration-200">
                    <div className="bg-gray-800 rounded-2xl w-full max-w-sm border border-gray-700 shadow-2xl overflow-hidden">
                        <div className={`p-6 flex flex-col items-center text-center ${confirmDialog.isDangerous ? 'bg-red-950/20' : 'bg-orange-950/20'}`}>
                            <div className={`w-16 h-16 rounded-full flex items-center justify-center mb-4 ${confirmDialog.isDangerous ? 'bg-red-500 text-white' : 'bg-orange-500 text-white'}`}>
                                <ShieldAlert size={32} />
                            </div>
                            <h3 className="text-xl font-black text-white uppercase tracking-tight mb-2">{confirmDialog.title}</h3>
                            <p className="text-gray-400 text-sm leading-relaxed">{confirmDialog.message}</p>
                        </div>
                        <div className="p-4 bg-gray-900/50 flex gap-3">
                            <button onClick={() => setConfirmDialog(prev => ({ ...prev, isOpen: false }))} className="flex-1 py-3 text-sm font-bold text-gray-400 hover:text-white uppercase">Hủy bỏ</button>
                            <button onClick={executeAction} className={`flex-1 py-3 text-sm font-black rounded-xl uppercase shadow-lg ${confirmDialog.isDangerous ? 'bg-red-600 hover:bg-red-500 text-white' : 'bg-blue-600 hover:bg-blue-500 text-white'}`}>Xác nhận</button>
                        </div>
                    </div>
                </div>
            )}

            {/* --- MAIN FORM MODAL --- */}
            {isModalOpen && (
                <div className="fixed inset-0 z-[500] bg-black/85 backdrop-blur-sm flex items-center justify-center p-4 overflow-y-auto">
                    <div className="bg-gray-800 rounded-xl w-full max-w-md p-6 border border-gray-700 shadow-2xl animate-in zoom-in-95 duration-200 my-auto">
                        <div className="flex justify-between items-center mb-6 border-b border-gray-700 pb-3">
                            <h3 className="text-xl font-bold text-white uppercase tracking-tighter flex items-center gap-2">
                                {modalType === 'TABLE' && <Table className="text-green-400"/>}
                                {modalType === 'LAYER' && <Globe className="text-cyan-400"/>}
                                {modalType === 'BASEMAP' && <MapIcon className="text-orange-400"/>}
                                {isEditMode ? "Chỉnh sửa" : "Thêm mới"} {modalType === 'TABLE' ? 'Bảng DB' : modalType === 'LAYER' ? 'Lớp chuyên đề' : 'Bản đồ nền'}
                            </h3>
                            <button onClick={() => setIsModalOpen(false)} className="text-gray-500 hover:text-white transition-colors"><X size={24}/></button>
                        </div>

                        <div className="space-y-5">
                            {/* Form cho TABLE */}
                            {modalType === 'TABLE' && (
                                <>
                                    {!isEditMode && (
                                        <div className="bg-gray-900 p-1 rounded flex gap-1 shadow-inner mb-4">
                                            <button onClick={() => setFormData({...formData, isExisting: false})} className={`flex-1 py-2 text-[10px] font-black rounded uppercase transition-all ${!formData.isExisting ? 'bg-green-600 text-white shadow-md' : 'text-gray-500 hover:text-gray-300'}`}>Tạo bảng mới</button>
                                            <button onClick={() => setFormData({...formData, isExisting: true})} className={`flex-1 py-2 text-[10px] font-black rounded uppercase transition-all ${formData.isExisting ? 'bg-blue-600 text-white shadow-md' : 'text-gray-500 hover:text-gray-300'}`}>Liên kết bảng sẵn có</button>
                                        </div>
                                    )}
                                    <div>
                                        <label className="text-[10px] text-gray-500 font-black uppercase block mb-1.5 ml-1">Tên bảng vật lý (PostgreSQL) <span className="text-red-500">*</span></label>
                                        <div className="relative">
                                            <input 
                                                className="w-full bg-gray-900 border border-gray-600 rounded-lg p-2.5 text-white font-mono text-sm outline-none focus:border-green-500" 
                                                placeholder="vd: thua_dat_phuong_1" 
                                                value={formData.tableName || ''} 
                                                onChange={e => setFormData({...formData, tableName: e.target.value.toLowerCase().trim()})}
                                            />
                                        </div>
                                        {isEditMode && (
                                            <p className="text-[9px] text-gray-500 mt-1 italic ml-1">
                                                Lưu ý: Thay đổi tên bảng ở đây chỉ cập nhật tham chiếu, không đổi tên bảng thật trong Database.
                                            </p>
                                        )}
                                    </div>
                                    <div>
                                        <label className="text-[10px] text-orange-400 font-black uppercase block mb-1.5 ml-1">Tên hiển thị trên bản đồ <span className="text-red-500">*</span></label>
                                        <input className="w-full bg-gray-900 border border-orange-900/30 rounded-lg p-2.5 text-white outline-none focus:border-orange-500 font-bold" placeholder="vd: Dữ liệu Thửa đất Phường 1" value={formData.displayName || ''} onChange={e => setFormData({...formData, displayName: e.target.value})} required />
                                    </div>
                                    <div>
                                        <label className="text-[10px] text-gray-500 font-black uppercase block mb-1.5 ml-1">Mô tả / Ghi chú</label>
                                        <textarea className="w-full bg-gray-900 border border-gray-600 rounded-lg p-2.5 text-white text-xs outline-none focus:border-green-500 h-20 resize-none" placeholder="Nhập ghi chú..." value={formData.description || ''} onChange={e => setFormData({...formData, description: e.target.value})}/>
                                    </div>
                                </>
                            )}

                            {/* Form cho LAYER CHUYÊN ĐỀ */}
                            {modalType === 'LAYER' && (
                                <>
                                    <div className="bg-gray-950 p-1 rounded flex gap-1 shadow-inner mb-4">
                                        <button onClick={() => setFormData({...formData, type: 'WMS'})} className={`flex-1 py-2 text-[10px] font-black rounded uppercase transition-all ${formData.type === 'WMS' ? 'bg-cyan-600 text-white shadow-md' : 'text-gray-500 hover:text-gray-300'}`}>Chuẩn WMS</button>
                                        <button onClick={() => setFormData({...formData, type: 'XYZ'})} className={`flex-1 py-2 text-[10px] font-black rounded uppercase transition-all ${formData.type === 'XYZ' ? 'bg-orange-600 text-white shadow-md' : 'text-gray-500 hover:text-gray-300'}`}>Chuẩn XYZ Tiles</button>
                                    </div>

                                    <div>
                                        <label className="text-[10px] text-gray-500 font-black uppercase block mb-1.5 ml-1">Tên hiển thị</label>
                                        <input className="w-full bg-gray-900 border border-gray-600 rounded-lg p-2.5 text-white outline-none focus:border-cyan-500" value={formData.name || ''} onChange={e => setFormData({...formData, name: e.target.value})}/>
                                    </div>

                                    {formData.type === 'WMS' && (
                                        <div>
                                            <label className="text-[10px] text-gray-500 font-black uppercase block mb-1.5 ml-1">Lớp (Workspace:Layer)</label>
                                            <input className="w-full bg-gray-900 border border-gray-600 rounded-lg p-2.5 text-white font-mono text-xs outline-none focus:border-cyan-500" placeholder="vd: hcm:binh_thanh_parcels" value={formData.layers || ''} onChange={e => setFormData({...formData, layers: e.target.value})}/>
                                        </div>
                                    )}

                                    <div>
                                        <label className="text-[10px] text-gray-500 font-black uppercase block mb-1.5 ml-1">
                                            {formData.type === 'WMS' ? 'URL GeoServer WMS' : 'URL XYZ Template (vd: .../{z}/{x}/{y}.png)'}
                                        </label>
                                        <input className="w-full bg-gray-900 border border-gray-600 rounded-lg p-2.5 text-white font-mono text-xs outline-none focus:border-cyan-500" value={formData.url || ''} onChange={e => setFormData({...formData, url: e.target.value})}/>
                                    </div>

                                    <div>
                                        <label className="flex items-center gap-2 cursor-pointer group mt-2">
                                            <div className={`w-5 h-5 rounded border border-gray-600 flex items-center justify-center transition-all ${formData.visible ? 'bg-cyan-600 border-cyan-600' : 'bg-gray-900'}`} onClick={() => setFormData({...formData, visible: !formData.visible})}>
                                                {formData.visible && <Check size={14} className="text-white"/>}
                                            </div>
                                            <span className="text-xs text-gray-300 font-bold uppercase tracking-wider">Cho phép hiển thị trên bản đồ</span>
                                        </label>
                                    </div>
                                </>
                            )}

                            {/* Form cho BASEMAP */}
                            {modalType === 'BASEMAP' && (
                                <>
                                    <div>
                                        <label className="text-[10px] text-gray-500 font-black uppercase block mb-1.5 ml-1">Tên bản đồ nền</label>
                                        <input className="w-full bg-gray-900 border border-gray-600 rounded-lg p-2.5 text-white outline-none focus:border-orange-500 font-bold" placeholder="vd: Bản đồ vệ tinh" value={formData.name || ''} onChange={e => setFormData({...formData, name: e.target.value})}/>
                                    </div>
                                    <div>
                                        <label className="text-[10px] text-gray-500 font-black uppercase block mb-1.5 ml-1">Loại nguồn dữ liệu</label>
                                        <select className="w-full bg-gray-900 border border-gray-600 rounded-lg p-2.5 text-white outline-none focus:border-orange-500" value={formData.type || 'XYZ'} onChange={e => setFormData({...formData, type: e.target.value})}>
                                            <option value="XYZ">XYZ Tiles</option>
                                            <option value="OSM">OpenStreetMap (OSM)</option>
                                        </select>
                                    </div>
                                    <div>
                                        <label className="text-[10px] text-gray-500 font-black uppercase block mb-1.5 ml-1">URL (XYZ Template)</label>
                                        <input className="w-full bg-gray-900 border border-gray-600 rounded-lg p-2.5 text-white font-mono text-xs outline-none focus:border-orange-500" placeholder="vd: https://{a-c}.tile.openstreetmap.org/{z}/{x}/{y}.png" value={formData.url || ''} onChange={e => setFormData({...formData, url: e.target.value})} disabled={formData.type === 'OSM'}/>
                                    </div>
                                    <div className="flex gap-4">
                                        <label className="flex items-center gap-2 cursor-pointer group">
                                            <div className={`w-5 h-5 rounded border border-gray-600 flex items-center justify-center transition-all ${formData.isDefault ? 'bg-orange-600 border-orange-600' : 'bg-gray-900'}`} onClick={() => setFormData({...formData, isDefault: !formData.isDefault})}>
                                                {formData.isDefault && <Check size={14} className="text-white"/>}
                                            </div>
                                            <span className="text-xs text-gray-300">Đặt làm mặc định</span>
                                        </label>
                                        <label className="flex items-center gap-2 cursor-pointer group">
                                            <div className={`w-5 h-5 rounded border border-gray-600 flex items-center justify-center transition-all ${formData.visible ? 'bg-green-600 border-green-600' : 'bg-gray-900'}`} onClick={() => setFormData({...formData, visible: !formData.visible})}>
                                                {formData.visible && <Check size={14} className="text-white"/>}
                                            </div>
                                            <span className="text-xs text-gray-300">Cho phép hiển thị</span>
                                        </label>
                                    </div>
                                </>
                            )}
                        </div>

                        <div className="flex justify-end gap-3 mt-8 pt-4 border-t border-gray-700">
                            <button onClick={() => setIsModalOpen(false)} className="px-4 py-2 text-gray-400 hover:text-white font-bold text-sm uppercase">Hủy bỏ</button>
                            <button onClick={handleSave} disabled={loading} className="bg-blue-600 hover:bg-blue-500 text-white px-8 py-2 rounded-lg font-black text-sm shadow-lg flex items-center gap-2 transition-all active:scale-95 disabled:opacity-50">
                                {loading ? <RefreshCw className="animate-spin" size={18}/> : <Save size={18}/>}
                                {isEditMode ? "LƯU THAY ĐỔI" : "XÁC NHẬN"}
                            </button>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

export default LayerManager;

