import express from 'express';
import os from 'os';

export default function(pool, logSystemAction, dbConfig) {
    const router = express.Router();

    // --- WMS LAYERS ---
    router.get('/wms-layers', async (req, res) => {
        try { 
            const result = await pool.query(`SELECT id, name, url, layers, visible, opacity, type, category FROM wms_layers ORDER BY name ASC`);
            res.json(result.rows); 
        } catch (e) { res.status(500).json({ error: e.message }); }
    });

    router.post('/wms-layers', async (req, res) => {
        const { name, url, layers, visible, opacity, type, category } = req.body;
        try {
            const id = 'ly-' + Date.now();
            await pool.query(
                `INSERT INTO wms_layers (id, name, url, layers, visible, opacity, type, category) VALUES ($1, $2, $3, $4, $5, $6, $7, $8)`,
                [id, name, url, layers, visible, opacity || 1, type || 'WMS', category || 'STANDARD']
            );
            await logSystemAction(req, 'ADD_LAYER', `Thêm lớp bản đồ: ${name}`);
            res.json({ status: 'ok' });
        } catch (e) { res.status(500).json({ error: e.message }); }
    });

    router.put('/wms-layers/:id', async (req, res) => {
        const { id } = req.params;
        const { name, url, layers, visible, opacity, type, category } = req.body;
        try {
            await pool.query(
                `UPDATE wms_layers SET name=$1, url=$2, layers=$3, visible=$4, opacity=$5, type=$6, category=$7 WHERE id=$8`,
                [name, url, layers, visible, opacity, type, category, id]
            );
            res.json({ status: 'ok' });
        } catch (e) { res.status(500).json({ error: e.message }); }
    });

    router.delete('/wms-layers/:id', async (req, res) => {
        try {
            await pool.query(`DELETE FROM wms_layers WHERE id = $1`, [req.params.id]);
            res.json({ status: 'ok' });
        } catch (e) { res.status(500).json({ error: e.message }); }
    });

    // --- BASEMAPS ---
    router.get('/basemaps', async (req, res) => {
        try { res.json((await pool.query(`SELECT id, name, url, type, is_default as "isDefault", visible FROM basemaps`)).rows); } catch (e) { res.status(500).json({ error: e.message }); }
    });

    router.post('/basemaps', async (req, res) => {
        const { name, url, type, isDefault, visible } = req.body;
        try {
            const id = 'bm-' + Date.now();
            if (isDefault) await pool.query(`UPDATE basemaps SET is_default = false`);
            await pool.query(`INSERT INTO basemaps (id, name, url, type, is_default, visible) VALUES ($1, $2, $3, $4, $5, $6)`, [id, name, url, type, isDefault, visible]);
            res.json({ status: 'ok' });
        } catch (e) { res.status(500).json({ error: e.message }); }
    });

    router.put('/basemaps/:id', async (req, res) => {
        const { id } = req.params;
        const { name, url, type, isDefault, visible } = req.body;
        try {
            if (isDefault) await pool.query(`UPDATE basemaps SET is_default = false`);
            await pool.query(`UPDATE basemaps SET name=$1, url=$2, type=$3, is_default=$4, visible=$5 WHERE id=$6`, [name, url, type, isDefault, visible, id]);
            res.json({ status: 'ok' });
        } catch (e) { res.status(500).json({ error: e.message }); }
    });

    router.delete('/basemaps/:id', async (req, res) => {
        try {
            await pool.query(`DELETE FROM basemaps WHERE id = $1`, [req.params.id]);
            res.json({ status: 'ok' });
        } catch (e) { res.status(500).json({ error: e.message }); }
    });

    // --- ROLE PERMISSIONS ---
    router.get('/role-permissions', async (req, res) => {
        try { res.json((await pool.query(`SELECT role, permissions FROM role_permissions`)).rows); } catch (e) { res.status(500).json({ error: e.message }); }
    });
    router.post('/role-permissions', async (req, res) => {
        try {
            await pool.query(`INSERT INTO role_permissions (role, permissions) VALUES ($1, $2) ON CONFLICT (role) DO UPDATE SET permissions = EXCLUDED.permissions`, [req.body.role, req.body.permissions]);
            res.json({ status: 'ok' });
        } catch (e) { res.status(500).json({ error: e.message }); }
    });

    // --- SYSTEM LOGS ---
    router.get('/logs', async (req, res) => {
        try { res.json((await pool.query(`SELECT id, user_id as "userId", user_name as "userName", action, details, timestamp FROM system_logs ORDER BY timestamp DESC LIMIT 200`)).rows); } catch (e) { res.status(500).json({ error: e.message }); }
    });

    // --- DB STATUS & SERVER INFO ---
    router.get('/db-check', async (req, res) => {
        try { await pool.query('SELECT 1'); res.json({ status: 'connected', dbName: dbConfig.database, host: dbConfig.host }); } catch (e) { res.json({ status: 'error', message: e.message }); }
    });
    router.get('/server-info', (req, res) => {
        res.json({ osType: os.type(), uptime: os.uptime(), freeMem: os.freemem(), cpuUsage: 0 });
    });

    // --- BACKUP V2 ---
    router.get('/backup/tables', async (req, res) => {
        try {
            const systemTables = ['users', 'branches', 'system_settings', 'land_prices', 'menu_items', 'wms_layers', 'basemaps', 'role_permissions', 'system_notifications', 'spatial_tables_registry'];
            const registryRes = await pool.query(`SELECT table_name FROM spatial_tables_registry`);
            const spatialTables = registryRes.rows.map(r => r.table_name);
            res.json({ system: systemTables, spatial: spatialTables });
        } catch (e) { res.status(500).json({ error: e.message }); }
    });

    router.post('/backup/create', async (req, res) => {
        const { tables } = req.body;
        if (!tables || !Array.isArray(tables) || tables.length === 0) return res.status(400).json({ error: "Vui lòng chọn ít nhất một bảng để sao lưu." });
        try {
            let sqlDump = `-- GeoMaster WebGIS SQL Dump\n-- Date: ${new Date().toISOString()}\n\n`;
            for (const table of tables) {
                const colRes = await pool.query(`SELECT column_name, data_type FROM information_schema.columns WHERE table_name = $1 ORDER BY ordinal_position`, [table]);
                if (colRes.rows.length === 0) continue;
                const columns = colRes.rows.map(r => r.column_name);
                const dataQuery = `SELECT ${colRes.rows.map(r => r.data_type === 'USER-DEFINED' ? `ST_AsEWKT("${r.column_name}") as "${r.column_name}"` : `"${r.column_name}"`).join(', ')} FROM "${table}"`;
                const dataRes = await pool.query(dataQuery);
                sqlDump += `-- Data for: ${table}\nDELETE FROM "${table}";\n`;
                for (const row of dataRes.rows) {
                    const values = columns.map(col => {
                        const val = row[col];
                        if (val === null) return 'NULL';
                        if (typeof val === 'string') return val.startsWith('SRID=') ? `ST_GeomFromEWKT('${val.replace(/'/g, "''")}')` : `'${val.replace(/'/g, "''")}'`;
                        return (val instanceof Date) ? `'${val.toISOString()}'` : val;
                    });
                    sqlDump += `INSERT INTO "${table}" (${columns.map(c => `"${c}"`).join(', ')}) VALUES (${values.join(', ')});\n`;
                }
                sqlDump += `\n`;
            }
            res.setHeader('Content-disposition', `attachment; filename=backup_${Date.now()}.sql`);
            res.setHeader('Content-type', 'text/plain');
            res.send(sqlDump);
        } catch (e) { res.status(500).json({ error: e.message }); }
    });

    return router;
}

import React, { useState, useEffect } from 'react';
import { adminService } from '../../services/mockBackend';
import { parcelApi } from '../../services/parcelApi';
import { WMSLayerConfig, BasemapConfig } from '../../types';
import { Layers, Database, Plus, Edit2, Trash2, X, Eye, EyeOff, Save, Table, Link2Off, RefreshCw, Map as MapIcon, CheckCircle2, Globe, AlertCircle, Check, ShieldAlert, Lock, Tags, Info } from 'lucide-react';

interface LayerManagerProps {
    dbStatus: any;
}

const LayerManager: React.FC<LayerManagerProps> = ({ dbStatus }) => {
    const [wmsLayers, setWmsLayers] = useState<WMSLayerConfig[]>([]);
    const [basemaps, setBasemaps] = useState<BasemapConfig[]>([]);
    const [spatialTables, setSpatialTables] = useState<any[]>([]);
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState<string | null>(null);

    // Modal State
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [modalType, setModalType] = useState<'LAYER' | 'TABLE' | 'BASEMAP' | null>(null);
    const [formData, setFormData] = useState<any>({});
    const [isEditMode, setIsEditMode] = useState(false);

    // Custom Confirmation Dialog State
    const [confirmDialog, setConfirmDialog] = useState<{
        isOpen: boolean;
        title: string;
        message: string;
        actionType: 'UNLINK' | 'DROP_TABLE' | 'DELETE_WMS' | 'DELETE_BASEMAP';
        targetId: string;
        targetName: string;
        isDangerous?: boolean;
    }>({
        isOpen: false,
        title: '',
        message: '',
        actionType: 'UNLINK',
        targetId: '',
        targetName: ''
    });

    useEffect(() => { loadData(); }, []);

    const loadData = async () => {
        setLoading(true);
        setError(null);
        try {
            const [layers, tables, maps] = await Promise.all([
                adminService.getWmsLayers().catch(() => []),
                parcelApi.manageTables.getAll().catch(() => []),
                adminService.getBasemaps().catch(() => [])
            ]);
            setWmsLayers(layers || []);
            setSpatialTables(tables || []);
            setBasemaps(maps || []);
        } catch (e: any) {
            setError("Không thể tải toàn bộ dữ liệu cấu hình.");
        } finally { setLoading(false); }
    };

    const openModal = (type: 'LAYER' | 'TABLE' | 'BASEMAP', item?: any) => {
        setModalType(type);
        setIsEditMode(!!item);

        if (type === 'LAYER') {
            setFormData(item ? { ...item, type: item.type || 'WMS', category: item.category || 'STANDARD' } : { name: '', url: '', layers: '', visible: true, opacity: 1, type: 'WMS', category: 'STANDARD' });
        } else if (type === 'TABLE') {
            if (item) {
                setFormData({
                    tableName: item.table_name,
                    originalName: item.table_name, 
                    displayName: item.display_name || item.table_name,
                    description: item.description || ''
                });
            } else {
                setFormData({
                    tableName: '',
                    displayName: '',
                    description: '',
                    isExisting: false
                });
            }
        } else if (type === 'BASEMAP') {
            setFormData(item ? { ...item } : { name: '', url: '', type: 'XYZ', isDefault: false, visible: true });
        }
        setIsModalOpen(true);
    };

    const handleSave = async () => {
        try {
            setLoading(true);
            let finalData = { ...formData };

            if (modalType === 'LAYER') {
                // TỰ ĐỘNG CHUẨN HÓA URL XYZ (Sửa lỗi ${z} sang {z})
                if (finalData.type === 'XYZ' && finalData.url) {
                    finalData.url = finalData.url.replace(/\${z}/g, '{z}').replace(/\${x}/g, '{x}').replace(/\${y}/g, '{y}');
                    if (!finalData.layers) finalData.layers = 'planning_tiles'; // Default layers name for XYZ
                }

                if (!finalData.name || !finalData.url) {
                    throw new Error("Vui lòng nhập Tên và URL cho lớp bản đồ.");
                }

                isEditMode ? await adminService.updateWmsLayer(finalData) : await adminService.addWmsLayer(finalData);
            } else if (modalType === 'BASEMAP') {
                isEditMode ? await adminService.updateBasemap(finalData) : await adminService.addBasemap(finalData);
            } else if (modalType === 'TABLE') {
                if (!finalData.tableName || !finalData.displayName) {
                    throw new Error("Vui lòng nhập đầy đủ Tên bảng vật lý và Tên hiển thị.");
                }
                if (isEditMode) {
                    await parcelApi.manageTables.rename(finalData.originalName, finalData.tableName, finalData.displayName, finalData.description);
                } else {
                    if (finalData.isExisting) {
                        await parcelApi.manageTables.link(finalData.tableName, finalData.displayName, finalData.description);
                    } else {
                        await parcelApi.manageTables.create(finalData.tableName, finalData.displayName, finalData.description);
                    }
                }
            }
            setIsModalOpen(false);
            await loadData();
        } catch (e: any) { 
            setError(e.message);
        } finally { setLoading(false); }
    };

    const toggleWmsVisibility = async (layer: WMSLayerConfig) => {
        try {
            setLoading(true);
            await adminService.updateWmsLayer({ ...layer, visible: !layer.visible });
            await loadData();
        } catch (e: any) {
            setError(e.message);
        } finally { setLoading(false); }
    };

    const triggerConfirm = (type: typeof confirmDialog['actionType'], id: string, name: string) => {
        let title = '';
        let message = '';
        let isDangerous = false;

        switch(type) {
            case 'UNLINK':
                title = 'Hủy liên kết Registry';
                message = `Bạn có chắc chắn muốn hủy liên kết bảng "${name}"? Thao tác này chỉ xóa thông tin quản lý trong phần mềm, dữ liệu trong Database của bạn vẫn được giữ nguyên.`;
                break;
            case 'DROP_TABLE':
                title = 'XÓA VĨNH VIỄN BẢNG';
                message = `CẢNH BÁO NGUY HIỂM: Bạn đang yêu cầu xóa vĩnh viễn bảng "${name}" khỏi Database. Hành động này sẽ XÓA TOÀN BỘ DỮ LIỆU và không thể khôi phục.`;
                isDangerous = true;
                break;
            case 'DELETE_WMS':
                title = 'Xóa lớp chuyên đề';
                message = `Xóa cấu hình lớp bản đồ chuyên đề "${name}"?`;
                break;
            case 'DELETE_BASEMAP':
                title = 'Xóa bản đồ nền';
                message = `Xóa cấu hình bản đồ nền "${name}"?`;
                break;
        }

        setConfirmDialog({
            isOpen: true,
            title,
            message,
            actionType: type,
            targetId: id,
            targetName: name,
            isDangerous
        });
    };

    const executeAction = async () => {
        const { actionType, targetId } = confirmDialog;
        setConfirmDialog(prev => ({ ...prev, isOpen: false }));
        setLoading(true);

        try {
            switch(actionType) {
                case 'UNLINK': await parcelApi.manageTables.unlink(targetId); break;
                case 'DROP_TABLE': await parcelApi.manageTables.delete(targetId); break;
                case 'DELETE_WMS': await adminService.deleteWmsLayer(targetId); break;
                case 'DELETE_BASEMAP': await adminService.deleteBasemap(targetId); break;
            }
            await loadData();
        } catch (e: any) {
            setError("Lỗi thực thi: " + e.message);
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="p-8 space-y-10 pb-24 max-w-7xl mx-auto font-sans">
            {error && (
                <div className="bg-red-900/20 border border-red-800 text-red-400 p-4 rounded-lg flex items-center justify-between gap-3 animate-in slide-in-from-top-2">
                    <div className="flex items-center gap-3">
                        <AlertCircle size={20} />
                        <span className="text-sm font-medium">{error}</span>
                    </div>
                    <button onClick={() => setError(null)} className="hover:text-white transition-colors"><X size={16}/></button>
                </div>
            )}

            {/* 1. DATABASE STATUS */}
            <div className="bg-gray-800 rounded-lg border border-gray-700 p-6 shadow-xl">
                <div className="flex justify-between items-center mb-4">
                    <h3 className="text-lg font-bold flex items-center gap-2 text-white uppercase tracking-tighter">
                        <Database className="text-blue-400" /> Kết nối Database PostGIS
                    </h3>
                    <button onClick={loadData} disabled={loading} className="text-xs text-blue-400 hover:text-blue-300 flex items-center gap-1 transition-colors disabled:opacity-50 font-black uppercase tracking-widest">
                        <RefreshCw size={12} className={loading ? "animate-spin" : ""} /> Làm mới dữ liệu
                    </button>
                </div>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4 text-sm font-mono text-gray-300 bg-gray-900 p-4 rounded border border-gray-700 shadow-inner">
                    <p><span className="text-gray-500">Trạng thái:</span> <span className="text-green-400 font-bold">ĐANG KẾT NỐI</span></p>
                    <p><span className="text-gray-500">Database:</span> <span className="text-blue-400">{dbStatus.dbName || 'dulieu_geogis'}</span></p>
                </div>
            </div>

            {/* 2. SPATIAL TABLES REGISTRY */}
            <div className="bg-gray-800 rounded-lg border border-gray-700 shadow-xl overflow-hidden">
                <div className="p-4 flex justify-between border-b border-gray-700 bg-gray-800/50">
                    <span className="font-semibold text-gray-100 flex items-center gap-2">
                        <Table size={18} className="text-green-400"/> Quản lý Bảng Dữ liệu (Registry)
                    </span>
                    <button onClick={() => openModal('TABLE')} className="bg-green-600 hover:bg-green-500 text-white px-4 py-1.5 rounded text-sm font-bold flex items-center gap-1 transition-all">
