                                        <button onClick={() => setFormData({...formData, category: 'STANDARD'})} className={`flex-1 py-2.5 text-[10px] font-black rounded-lg transition-all ${formData.category === 'STANDARD' ? 'bg-gray-700 text-white' : 'text-gray-600 hover:text-gray-400'}`}>CHUYÊN ĐỀ</button>
                                        <button onClick={() => setFormData({...formData, category: 'PLANNING'})} className={`flex-1 py-2.5 text-[10px] font-black rounded-lg transition-all ${formData.category === 'PLANNING' ? 'bg-purple-600 text-white shadow-lg' : 'text-gray-600 hover:text-gray-400'}`}>QUY HOẠCH</button>
                                    </div>
                                </div>
                            </div>

                            <div>
                                <label className="text-[10px] text-gray-500 font-black uppercase mb-2 block tracking-widest">Tên hiển thị *</label>
