        image: new style.Circle({ radius: 5, stroke: new style.Stroke({ color: '#3b82f6', width: 2 }), fill: new style.Fill({ color: '#fff' }) })
    });

    const smartMapProperties = (props: any) => {
        const findVal = (keys: string[]) => {
            for (const k of keys) {
                if (props[k] !== undefined && props[k] !== null && props[k] !== '') return props[k];
                const lower = k.toLowerCase();
                if (props[lower] !== undefined && props[lower] !== null && props[lower] !== '') return props[lower];
            }
            return null;
        };
        return {
            ...props,
            so_to: findVal(['sodoto', 'so_to', 'shbando', 'sh_ban_do', 'tobando', 'tờ']),
            so_thua: findVal(['sothua', 'so_thua', 'shthua', 'sh_thua', 'thửa']),
            ownerName: findVal(['tenchu', 'ten_chu', 'ten_chu_sd', 'owner']),
            area: parseFloat(findVal(['dientich', 'dien_tich', 'area']) || 0),
            landType: findVal(['loaidat', 'kyhieumucd', 'mucdich']) || 'N/A',
            address: findVal(['diachi', 'dia_chi', 'dc']) || ''
        };
    };

    const formatLength = (line: LineString) => {
        const length = getLength(line);
        return length > 100 ? (length / 1000).toFixed(2) + ' km' : length.toFixed(2) + ' m';
    };

    const formatArea = (polygon: Polygon) => {
        const area = getArea(polygon);
        return area > 10000 ? (area / 10000).toFixed(2) + ' ha' : area.toFixed(2) + ' m²';
    };

    const handlePrint = async (parcel: LandParcel) => {
        setIsPrinting(true);
        setPrintingParcel(parcel);
        setTimeout(async () => {
            const element = document.getElementById('print-template');
            if (!element) { setIsPrinting(false); setPrintingParcel(null); return; }
            try {
                const canvas = await html2canvas(element, { scale: 2.5, useCORS: true, logging: false, backgroundColor: '#ffffff' });
                const pdf = new jsPDF('p', 'mm', 'a4');
                const pdfWidth = pdf.internal.pageSize.getWidth();
                const pdfHeight = pdf.internal.pageSize.getHeight();
                const imgWidth = pdfWidth;
                const imgHeight = (canvas.height * pdfWidth) / canvas.width;
                let heightLeft = imgHeight;
                let position = 0;
                const imgData = canvas.toDataURL('image/jpeg', 1.0);
                pdf.addImage(imgData, 'JPEG', 0, position, imgWidth, imgHeight);
                heightLeft -= pdfHeight;
                while (heightLeft > 0) { position -= pdfHeight; pdf.addPage(); pdf.addImage(imgData, 'JPEG', 0, position, imgWidth, imgHeight); heightLeft -= pdfHeight; }
                pdf.save(`TrichLuc_To${parcel.properties.so_to}_Thua${parcel.properties.so_thua}.pdf`);
            } catch (error) { console.error("Print Error:", error); } finally { setIsPrinting(false); setPrintingParcel(null); }
        }, 1200);
    };

    const handleSelectResult = useCallback((parcel: LandParcel, fallbackCoord?: Coordinate) => {
        if (!mapInstance.current || !highlightLayer.current) return;
        const normalizedParcel = { ...parcel, properties: smartMapProperties(parcel.properties) };
        setSelectedParcel(normalizedParcel);
        const source = highlightLayer.current.getSource();
        source?.clear();
        let popupPos = fallbackCoord;
        if (parcel.geometry) {
            try {
                const format = new GeoJSON();
                let firstCoord: any = null;
                if (parcel.geometry.type === 'Polygon') firstCoord = parcel.geometry.coordinates[0][0];
                else if (parcel.geometry.type === 'MultiPolygon') firstCoord = parcel.geometry.coordinates[0][0][0];
                else if (parcel.geometry.type === 'Point') firstCoord = parcel.geometry.coordinates;

                let dataProj = 'EPSG:4326';
                if (firstCoord) {
                    const x = Math.abs(firstCoord[0]);
                    const y = Math.abs(firstCoord[1]);
                    if (x > 2000000 || y > 2000000) dataProj = 'EPSG:3857';
                    else if (x > 300000 && x < 900000) dataProj = 'EPSG:9210';
                }
                const geometry = format.readGeometry(parcel.geometry, { dataProjection: dataProj, featureProjection: 'EPSG:3857' });
                if (geometry) {
                    const feature = new Feature({ geometry });
                    source?.addFeature(feature);
                    const extent = geometry.getExtent();
                    if (extent && !isExtentEmpty(extent)) {
                        popupPos = getExtentCenter(extent);
                        mapInstance.current.getView().fit(extent, { padding: [120, 120, 120, 120], duration: 800, maxZoom: 21 });
                    }
                }
            } catch (err) {}
        }
        if (popupPos) overlayInstance.current?.setPosition(popupPos);
    }, []);

    const handleActivateLayer = async (id: string) => {
        setActiveLayerId(id);
        if (!visibleLayerIds.includes(id)) setVisibleLayerIds(prev => [...prev, id]);
        const layer = availableLayers.find(l => l.id === id);
        if (layer && layer.type !== 'XYZ') {
            const tableName = layer.layers.includes(':') ? layer.layers.split(':')[1] : layer.layers;
            try {
                const res = await fetch(`${API_URL}/api/data/${tableName}/extent`);
                if (res.ok) {
                    const bounds = await res.json();
                    if (bounds && bounds.xmin !== undefined) {
                        let sourceProj = 'EPSG:4326';
                        if (Math.abs(bounds.xmin) > 100000) sourceProj = 'EPSG:9210';
                        const extent = proj.transformExtent([bounds.xmin, bounds.ymin, bounds.xmax, bounds.ymax], sourceProj, 'EPSG:3857');
                        if (mapInstance.current) mapInstance.current.getView().fit(extent, { padding: [50, 50, 50, 50], duration: 1000, maxZoom: 19 });
                    }
                }
            } catch (e) {}
        }
    };

    const handleSearchCoordinate = (lat: number, lon: number) => {
        const coords = proj.fromLonLat([lon, lat]);
        if (locationLayer.current) {
            const source = locationLayer.current.getSource();
            source?.getFeatures().forEach(f => { if (f.get('type') === 'search_result') source.removeFeature(f); });
            const feature = new Feature({ geometry: new Point(coords) });
            feature.set('type', 'search_result');
            source?.addFeature(feature);
        }
        mapInstance.current?.getView().animate({ center: coords, zoom: 18, duration: 1000 });
    };

    const initData = async () => {
        try {
            const [layers, tables, maps] = await Promise.all([
                gisService.getLayers().catch(() => []), 
                gisService.getSpatialTables().catch(() => []),
                gisService.getBasemaps().catch(() => [])
            ]);

            setAvailableLayers(layers);
            setVisibleLayerIds(layers.filter(l => l.visible).map(l => l.id));
            setSpatialTables(tables);
            setBasemaps(maps);
            const defMap = maps.find(m => m.id === activeBasemapId) || maps.find(m => m.isDefault) || maps[0];
            if (defMap) setActiveBasemapId(defMap.id);
            if (layers.length && !activeLayerId) setActiveLayerId(layers[0].id);
        } catch (e) { console.error(e); } finally { setIsInitialLoading(false); }
    };

    useEffect(() => {
        if (!mapElement.current || mapInstance.current) return;
        const map = new Map({
            target: mapElement.current,
            layers: [
                new TileLayer({ zIndex: 0 }),
                new LayerGroup({ zIndex: 10 }),
                new VectorLayer({ source: new VectorSource(), zIndex: 10000, style: highlightStyle }),
                new VectorLayer({ source: new VectorSource(), zIndex: 20000, style: locationStyle }),
                new VectorLayer({ source: measureSource.current, zIndex: 30000, style: measureStyle }),
            ],
            view: new View({ center: proj.fromLonLat([106.619, 11.284]), zoom: 13, minZoom: 5, maxZoom: 22 }),
            controls: defaultControls({ attribution: false })
        });
        const layers = map.getLayers().getArray();
        baseLayerRef.current = layers[0] as TileLayer<any>;
        wmsLayerGroup.current = layers[1] as LayerGroup;
        highlightLayer.current = layers[2] as VectorLayer<VectorSource>;
        locationLayer.current = layers[3] as VectorLayer<VectorSource>;
        overlayInstance.current = new Overlay({ element: popupElement.current!, autoPan: { animation: { duration: 250 } }, positioning: 'bottom-center' });
        map.addOverlay(overlayInstance.current);

        map.on('singleclick', async (evt) => {
            if (measureMode) return; 
            const view = map.getView();
            const layers = wmsLayerGroup.current?.getLayers().getArray() || [];
            if (layers.length === 0) return;
            const targetConfig = availableLayers.find(l => l.id === activeLayerId);
            if (targetConfig?.type === 'XYZ') return;
            const targetLayer = (layers.find(l => l.get('layerId') === activeLayerId) || layers[layers.length - 1]) as TileLayer<any>;
            if (!targetLayer.getSource()?.getFeatureInfoUrl) return;
            const url = targetLayer.getSource().getFeatureInfoUrl(evt.coordinate, view.getResolution()!, view.getProjection(), { 'INFO_FORMAT': 'application/json', 'FEATURE_COUNT': 1 });
            if (url) {
                setIsQuerying(true);
                overlayInstance.current?.setPosition(undefined);
                setSelectedParcel(null);
                highlightLayer.current?.getSource()?.clear();
                try {
                    const res = await fetch(url);
                    const data = await res.json();
                    if (data.features?.length > 0) {
                        const f = data.features[0];
                        handleSelectResult({ id: f.id, gid: f.properties.gid || parseInt(f.id.split('.').pop()||'0'), geometry: f.geometry, properties: f.properties }, evt.coordinate);
                    }
                } catch (e) {} finally { setIsQuerying(false); }
            }
        });
        map.on('pointermove', (evt) => { if (!evt.dragging) setMouseCoord(proj.toLonLat(evt.coordinate)); });
        map.getView().on('change:rotation', () => setMapRotation(map.getView().getRotation()));
        map.getView().on('change:resolution', () => setMapZoom(map.getView().getZoom() || 0));
        const resizeObserver = new ResizeObserver(() => map.updateSize());
        resizeObserver.observe(mapElement.current);
        mapInstance.current = map;
        initData();
        return () => resizeObserver.disconnect();
    }, [handleSelectResult, measureMode, activeLayerId]);

    useEffect(() => {
        if (!mapInstance.current || !measureMode) { if (drawInteraction.current) mapInstance.current?.removeInteraction(drawInteraction.current); return; }
        const map = mapInstance.current;
        drawInteraction.current = new Draw({ source: measureSource.current, type: measureMode, style: measureStyle });
        map.addInteraction(drawInteraction.current);
        let listener: any;
        drawInteraction.current.on('drawstart', (evt) => {
            const feature = evt.feature;
            const tooltipElement = document.createElement('div');
            tooltipElement.className = 'bg-black/80 text-white px-2 py-1 rounded text-[10px] font-bold shadow-xl backdrop-blur-sm border border-white/20 pointer-events-none whitespace-nowrap';
            const tooltip = new Overlay({ element: tooltipElement, offset: [0, -15], positioning: 'bottom-center', stopEvent: false, insertFirst: false });
            map.addOverlay(tooltip);
            listener = feature.getGeometry()?.on('change', (evt: any) => {
                const geom = evt.target;
                let output = '';
                let tooltipCoord: Coordinate | undefined;
                if (geom instanceof Polygon) { output = formatArea(geom); tooltipCoord = geom.getInteriorPoint().getCoordinates(); }
                else if (geom instanceof LineString) { output = formatLength(geom); tooltipCoord = geom.getLastCoordinate(); }
                tooltipElement.innerHTML = output;
                if (tooltipCoord) tooltip.setPosition(tooltipCoord);
            });
        });
        drawInteraction.current.on('drawend', () => { if (listener) unByKey(listener); setMeasureMode(null); });
        return () => { if (drawInteraction.current) map.removeInteraction(drawInteraction.current); };
    }, [measureMode]);

    const handleClearMeasure = () => { measureSource.current.clear(); mapInstance.current?.getOverlays().getArray().filter(o => o !== overlayInstance.current).forEach(o => mapInstance.current?.removeOverlay(o)); };
    const handleZoomIn = () => { const view = mapInstance.current?.getView(); if (view) view.animate({ zoom: (view.getZoom() || 0) + 1, duration: 250 }); };
    const handleZoomOut = () => { const view = mapInstance.current?.getView(); if (view) view.animate({ zoom: (view.getZoom() || 0) - 1, duration: 250 }); };
    const handleResetRotation = () => mapInstance.current?.getView().animate({ rotation: 0, duration: 500 });
    const handleLocate = () => {
        if (!navigator.geolocation) return alert("Không hỗ trợ định vị.");
        setIsLocating(true);
        navigator.geolocation.getCurrentPosition( (pos) => {
                const coords = proj.fromLonLat([pos.coords.longitude, pos.coords.latitude]);
                if (locationLayer.current) {
                    const source = locationLayer.current.getSource();
                    source?.getFeatures().forEach(f => { const type = f.get('type'); if (type === 'accuracy' || type === 'position') source.removeFeature(f); });
                    source?.addFeature(new Feature({ geometry: new GeomCircle(coords, pos.coords.accuracy) }).set('type', 'accuracy') as any);
                    source?.addFeature(new Feature({ geometry: new Point(coords) }).set('type', 'position') as any);
                }
                mapInstance.current?.getView().animate({ center: coords, zoom: Math.max(18, mapInstance.current.getView().getZoom() || 0), duration: 1000 });
                setIsLocating(false);
            }, () => setIsLocating(false), { enableHighAccuracy: true, timeout: 15000, maximumAge: 0 } );
    };

    // --- Cập nhật Basemap (Bản đồ nền) ---
    useEffect(() => {
        if (!baseLayerRef.current || !activeBasemapId || basemaps.length === 0) return;
        const config = basemaps.find(m => m.id === activeBasemapId);
        if (!config) return;

        let source;
        if (config.type === 'OSM') {
            source = new OSM({ crossOrigin: 'anonymous' });
        } else {
            // PROXY BẮT BUỘC: Đảm bảo link XYZ đi qua Proxy để tránh CORS
            const rawUrl = config.url.startsWith('/') ? `${API_URL}${config.url}` : config.url;
            const proxiedUrl = `${API_URL}/api/proxy/forward?url=${encodeURIComponent(rawUrl)}`
                .replace(/%7Bz%7D/g, '{z}')
                .replace(/%7Bx%7D/g, '{x}')
                .replace(/%7By%7D/g, '{y}');
            source = new XYZ({ url: proxiedUrl, crossOrigin: 'anonymous' });
        }
        baseLayerRef.current.setSource(source);
    }, [activeBasemapId, basemaps]);

    // --- Cập nhật Overlay Layers (Quy hoạch/Chuyên đề) ---
    useEffect(() => {
        if (!wmsLayerGroup.current) return;
        const olLayers = availableLayers.filter(l => visibleLayerIds.includes(l.id)).map(config => {
            let source;
            // TỰ ĐỘNG NHẬN DIỆN XYZ: Nếu URL chứa placeholder {z} thì ép kiểu XYZ kể cả khi DB lưu là WMS
            const isXYZ = config.type === 'XYZ' || (config.url && (config.url.includes('{z}') || config.url.includes('${z}')));

            if (isXYZ) {
                const cleanUrl = config.url.replace(/\${z}/g, '{z}').replace(/\${x}/g, '{x}').replace(/\${y}/g, '{y}');
                const proxiedUrl = `${API_URL}/api/proxy/forward?url=${encodeURIComponent(cleanUrl)}`
                    .replace(/%7Bz%7D/g, '{z}')
                    .replace(/%7Bx%7D/g, '{x}')
                    .replace(/%7By%7D/g, '{y}');
                source = new XYZ({ url: proxiedUrl, crossOrigin: 'anonymous' });
            } else {
                // WMS Proxy
                source = new TileWMS({ 
                    url: `${API_URL}/api/proxy/forward?url=${encodeURIComponent(config.url)}`, 
                    params: { 'LAYERS': config.layers, 'TILED': true, 'TRANSPARENT': true, 'FORMAT': 'image/png' }, 
                    crossOrigin: 'anonymous' 
                });
            }

            // THỨ TỰ HIỂN THỊ (Z-INDEX)
            let zIndex = 10;
            if (config.category === 'PLANNING') zIndex = 100; // Quy hoạch luôn nằm trên
            if (activeLayerId === config.id) zIndex += 50; // Lớp đang chọn ưu tiên hơn

            const layer = new TileLayer({ source: source, opacity: Number(config.opacity ?? 1), zIndex: zIndex });
            layer.set('layerId', config.id);
            return layer;
        });
        wmsLayerGroup.current.setLayers(new Collection(olLayers));
    }, [availableLayers, visibleLayerIds, activeLayerId]);

    return (
        <div className="relative w-full h-full bg-slate-950 flex flex-col min-h-0 overflow-hidden font-sans">
            {isInitialLoading && (
                <div className="absolute inset-0 z-[1000] bg-slate-900 flex flex-col items-center justify-center text-white gap-4">
                    <Loader2 className="animate-spin text-blue-500" size={48} />
                    <p className="font-display uppercase tracking-[0.3em] text-[10px] text-blue-400 font-black animate-pulse">GeoMaster Engine Loading...</p>
                </div>
            )}
            <div className="absolute bottom-6 left-6 z-[400] flex flex-col gap-2 pointer-events-none">
                {mouseCoord && (
                    <div className="bg-slate-900/80 backdrop-blur-md border border-slate-700/50 px-3 py-1.5 rounded-xl shadow-2xl flex items-center gap-3 animate-in fade-in duration-300">
                        <div className="flex items-center gap-1.5 text-blue-400"><MousePointer2 size={12}/><span className="text-[9px] font-black uppercase tracking-[0.1em]">Tọa độ</span></div>
                        <div className="flex gap-4 font-mono text-[11px] font-bold text-gray-100">
                            <div className="flex items-baseline gap-1"><span className="text-gray-500 text-[9px]">X:</span><span>{mouseCoord[0].toFixed(6)}</span></div>
                            <div className="flex items-baseline gap-1"><span className="text-gray-500 text-[9px]">Y:</span><span>{mouseCoord[1].toFixed(6)}</span></div>
                        </div>
                    </div>
                )}
                <div className="w-fit bg-slate-900/80 backdrop-blur-md border border-slate-700/50 px-2.5 py-1 rounded-lg flex items-center gap-2">
                    <div className="w-1.5 h-1.5 rounded-full bg-green-500 animate-pulse"></div>
                    <span className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Zoom: <span className="text-white ml-1">{Math.round(mapZoom)}</span></span>
                </div>
            </div>
            {isPrinting && ( <div className="absolute inset-0 z-[2000] bg-black/70 backdrop-blur-md flex flex-col items-center justify-center text-white gap-4"> <Printer className="animate-bounce text-orange-500" size={64} /> <div className="text-center"> <p className="font-display font-bold text-xl uppercase tracking-tighter">Đang xuất trích lục đa trang</p> </div> </div> )}
            <div ref={mapElement} className="flex-1 w-full relative" />
            <MeasureTools activeMode={measureMode} onModeChange={setMeasureMode} onClear={handleClearMeasure} />
            <div ref={popupElement} className="absolute bottom-0 left-0 pointer-events-none"> {selectedParcel && ( <div className="pointer-events-auto"> <ParcelPopup parcel={selectedParcel} user={user} onClose={() => { overlayInstance.current?.setPosition(undefined); setSelectedParcel(null); highlightLayer.current?.getSource()?.clear(); }} onPrint={handlePrint} /> </div> )} </div>
            <div className="fixed -left-[4000px] top-0 opacity-0 pointer-events-none overflow-hidden"> {printingParcel && <PrintTemplate parcel={printingParcel} user={user} systemSettings={systemSettings} />} </div>
            <div className="absolute bottom-6 right-6 z-[400] flex flex-col gap-3">
                {Math.abs(mapRotation) > 0.01 && ( <button onClick={handleResetRotation} className="p-3 bg-white rounded-full shadow-2xl text-orange-600 hover:bg-orange-50 transition-all"><Compass size={24} style={{ transform: `rotate(${-mapRotation}rad)` }}/></button> )}
                <div className="flex flex-col bg-white rounded-2xl shadow-2xl border border-gray-100 overflow-hidden"> <button onClick={handleZoomIn} className="p-3.5 text-gray-700 hover:bg-gray-50 border-b border-gray-100 transition-colors"><Plus size={20}/></button> <button onClick={handleZoomOut} className="p-3.5 text-gray-700 hover:bg-gray-50 transition-colors"><Minus size={20}/></button> </div>
                <button onClick={handleLocate} className={`p-3.5 rounded-full shadow-2xl text-white transition-all ${isLocating ? 'bg-gray-400' : 'bg-blue-600 hover:bg-blue-700'}`}><Crosshair size={24} className={isLocating ? "animate-spin" : ""}/></button>
            </div>
            <SearchPanel isOpen={isSearchOpen} onToggle={() => setIsSearchOpen(!isSearchOpen)} spatialTables={spatialTables} onSelectResult={p => handleSelectResult(p)} onSearchCoordinate={handleSearchCoordinate} />
            <LayerControl isOpen={isLayerMenuOpen} onToggleMenu={() => setIsLayerMenuOpen(!isLayerMenuOpen)} basemaps={basemaps} activeBasemapId={activeBasemapId} onBaseLayerChange={setActiveBasemapId} availableLayers={availableLayers} visibleLayerIds={visibleLayerIds} activeLayerId={activeLayerId} onToggleWMS={id => setVisibleLayerIds(prev => prev.includes(id) ? prev.filter(x => x !== id) : [...prev, id])} onSetActiveWMS={handleActivateLayer} onOpacityChange={(id, opacity) => setAvailableLayers(prev => prev.map(l => l.id === id ? { ...l, opacity } : l))} />
        </div>
    );
};

export default MapPage;

import express from 'express';
const router = express.Router();

router.get('/vietbando', async (req, res) => {
    const { z, x, y } = req.query;
    if (!z || !x || !y) return res.status(400).send("Missing tile coordinates");
    const targetUrl = `http://images.vietbando.com/ImageLoader/GetImage.ashx?Ver=2016&LayerIds=VBD&Y=${y}&X=${x}&Level=${z}`;

    try {
        const response = await fetch(targetUrl, {
            headers: {
                'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36',
                'Referer': 'http://vietbando.com/',
                'Accept': 'image/webp,image/apng,image/*,*/*;q=0.8'
            }
        });

        if (!response.ok) return res.status(404).send('Tile not found'); 
        const buffer = Buffer.from(await response.arrayBuffer());
        res.set('Content-Type', response.headers.get('content-type') || 'image/png');
        res.set('Cache-Control', 'public, max-age=86400');
        res.set('Access-Control-Allow-Origin', '*');
        res.send(buffer);
    } catch (error) {
        res.status(404).send('Tile error');
    }
});

router.get('/forward', async (req, res) => {
    let targetBaseUrl = req.query.url;
    if (!targetBaseUrl) return res.status(400).send("Missing 'url' parameter");

    try {
        targetBaseUrl = decodeURIComponent(targetBaseUrl);
        const finalUrl = new URL(targetBaseUrl);

        // Kiểm tra xem đây có phải là yêu cầu XYZ hay WMS
        const isXYZ = targetBaseUrl.includes('{z}') || targetBaseUrl.includes('{x}') || targetBaseUrl.includes('{y}');

        // Nếu là WMS, chuyển tiếp các tham số GetMap/GetFeatureInfo
        if (!isXYZ) {
            Object.keys(req.query).forEach(key => {
                if (key !== 'url') {
                    finalUrl.searchParams.set(key, req.query[key]);
                }
            });
            const layers = finalUrl.searchParams.get('LAYERS');
            if (layers && !finalUrl.searchParams.get('QUERY_LAYERS')) {
                finalUrl.searchParams.set('QUERY_LAYERS', layers);
            }
        }

        const response = await fetch(finalUrl.toString(), {
            headers: {
                'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/122.0.0.0 Safari/537.36',
                'Accept': 'image/webp, image/png, image/jpeg, image/*, */*',
                'Referer': finalUrl.origin
            }
        });

        if (!response.ok) {
            console.error(`[Proxy Fail] Status: ${response.status} URL: ${finalUrl.toString()}`);
            return res.status(response.status).send("Proxy error");
        }

        const contentType = response.headers.get('content-type');
        if (contentType) res.set('Content-Type', contentType);

        res.set('Access-Control-Allow-Origin', '*');
        res.set('Cache-Control', 'public, max-age=3600'); // Cache 1h để tăng tốc

        const buffer = Buffer.from(await response.arrayBuffer());
        res.send(buffer);
    } catch (e) {
        console.error(`[Proxy Critical] Error fetching: ${targetBaseUrl} -> ${e.message}`);
        res.status(502).json({ error: "Gateway Error", message: e.message });
    }
});

export default router;

import React, { useState, useEffect } from 'react';
import { adminService } from '../../services/mockBackend';
import { parcelApi } from '../../services/parcelApi';
import { WMSLayerConfig, BasemapConfig } from '../../types';
import { Layers, Database, Plus, Edit2, Trash2, X, Eye, EyeOff, Save, Table, Link2Off, RefreshCw, Map as MapIcon, CheckCircle2, Globe, AlertCircle, Check, ShieldAlert, Lock, Tags, Info, Shield, ExternalLink } from 'lucide-react';

interface LayerManagerProps {
    dbStatus: any;
}

const LayerManager: React.FC<LayerManagerProps> = ({ dbStatus }) => {
    const [wmsLayers, setWmsLayers] = useState<WMSLayerConfig[]>([]);
    const [basemaps, setBasemaps] = useState<BasemapConfig[]>([]);
    const [spatialTables, setSpatialTables] = useState<any[]>([]);
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState<string | null>(null);

    // Modal State
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [modalType, setModalType] = useState<'LAYER' | 'TABLE' | 'BASEMAP' | null>(null);
    const [formData, setFormData] = useState<any>({});
    const [isEditMode, setIsEditMode] = useState(false);

    // Custom Confirmation Dialog State
    const [confirmDialog, setConfirmDialog] = useState<{
        isOpen: boolean;
        title: string;
        message: string;
        actionType: 'UNLINK' | 'DROP_TABLE' | 'DELETE_WMS' | 'DELETE_BASEMAP';
        targetId: string;
        targetName: string;
        isDangerous?: boolean;
    }>({
        isOpen: false,
        title: '',
        message: '',
        actionType: 'UNLINK',
        targetId: '',
        targetName: ''
    });

    useEffect(() => { loadData(); }, []);

    const loadData = async () => {
        setLoading(true);
        setError(null);
        try {
            const [layers, tables, maps] = await Promise.all([
                adminService.getWmsLayers().catch(() => []),
                parcelApi.manageTables.getAll().catch(() => []),
                adminService.getBasemaps().catch(() => [])
            ]);
            setWmsLayers(layers || []);
            setSpatialTables(tables || []);
            setBasemaps(maps || []);
        } catch (e: any) {
            setError("Không thể tải toàn bộ dữ liệu cấu hình. Vui lòng kiểm tra Server.");
        } finally { setLoading(false); }
    };

    const openModal = (type: 'LAYER' | 'TABLE' | 'BASEMAP', item?: any) => {
        setModalType(type);
        setIsEditMode(!!item);

        if (type === 'LAYER') {
            setFormData(item ? { ...item, type: item.type || 'WMS', category: item.category || 'STANDARD' } : { name: '', url: '', layers: '', visible: true, opacity: 0.8, type: 'XYZ', category: 'PLANNING' });
        } else if (type === 'TABLE') {
            setFormData(item ? {
                tableName: item.table_name,
                originalName: item.table_name, 
                displayName: item.display_name || item.table_name,
                description: item.description || ''
            } : {
                tableName: '',
                displayName: '',
                description: '',
                isExisting: false
            });
        } else if (type === 'BASEMAP') {
            setFormData(item ? { ...item } : { name: '', url: '', type: 'XYZ', isDefault: false, visible: true });
        }
        setIsModalOpen(true);
    };

    const handleSave = async () => {
        try {
            setLoading(true);
            let finalData = { ...formData };

            if (modalType === 'LAYER') {
                if (finalData.type === 'XYZ' && finalData.url) {
                    finalData.url = finalData.url.replace(/\${z}/g, '{z}').replace(/\${x}/g, '{x}').replace(/\${y}/g, '{y}');
                    if (!finalData.layers) finalData.layers = 'tiles';
                }
                if (!finalData.name || !finalData.url) throw new Error("Vui lòng nhập đầy đủ Tên và URL.");
                isEditMode ? await adminService.updateWmsLayer(finalData) : await adminService.addWmsLayer(finalData);
            } else if (modalType === 'BASEMAP') {
                isEditMode ? await adminService.updateBasemap(finalData) : await adminService.addBasemap(finalData);
            } else if (modalType === 'TABLE') {
                if (isEditMode) await parcelApi.manageTables.rename(finalData.originalName, finalData.tableName, finalData.displayName, finalData.description);
                else {
                    if (finalData.isExisting) await parcelApi.manageTables.link(finalData.tableName, finalData.displayName, finalData.description);
                    else await parcelApi.manageTables.create(finalData.tableName, finalData.displayName, finalData.description);
                }
            }
            setIsModalOpen(false);
            await loadData();
        } catch (e: any) { 
            setError(e.message);
        } finally { setLoading(false); }
    };

    const executeAction = async () => {
        const { actionType, targetId } = confirmDialog;
        setConfirmDialog(prev => ({ ...prev, isOpen: false }));
        setLoading(true);

        try {
            switch(actionType) {
                case 'UNLINK': await parcelApi.manageTables.unlink(targetId); break;
                case 'DROP_TABLE': await parcelApi.manageTables.delete(targetId); break;
                case 'DELETE_WMS': await adminService.deleteWmsLayer(targetId); break;
                case 'DELETE_BASEMAP': await adminService.deleteBasemap(targetId); break;
            }
            await loadData();
        } catch (e: any) { setError(e.message); } finally { setLoading(false); }
    };

    return (
        <div className="p-8 space-y-10 pb-24 max-w-7xl mx-auto font-sans">
            {error && (
                <div className="bg-red-900/20 border border-red-800 text-red-400 p-4 rounded-lg flex items-center justify-between gap-3 animate-in slide-in-from-top-2">
                    <div className="flex items-center gap-3">
                        <AlertCircle size={20} />
                        <span className="text-sm font-medium">{error}</span>
                    </div>
                    <button onClick={() => setError(null)} className="hover:text-white transition-colors"><X size={16}/></button>
                </div>
            )}

            {/* 1. DATABASE STATUS */}
            <div className="bg-gray-800 rounded-3xl border border-gray-700 p-6 shadow-xl relative overflow-hidden group">
                <div className="absolute top-0 left-0 w-1 h-full bg-blue-500 group-hover:w-2 transition-all"></div>
                <div className="flex justify-between items-center mb-4">
                    <h3 className="text-lg font-black flex items-center gap-2 text-white uppercase tracking-tighter">
                        <Database className="text-blue-400" /> Hệ thống Dữ liệu
                    </h3>
                    <button onClick={loadData} disabled={loading} className="px-4 py-2 bg-gray-900 border border-gray-700 rounded-xl text-[10px] text-blue-400 hover:text-white hover:bg-blue-600 transition-all flex items-center gap-2 font-black uppercase">
                        <RefreshCw size={12} className={loading ? "animate-spin" : ""} /> Làm mới
                    </button>
                </div>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4 text-xs font-mono">
                    <div className="bg-gray-950 p-3 rounded-xl border border-gray-700 flex items-center justify-between">
                        <span className="text-gray-500">PostgreSQL Status:</span>
                        <span className="text-green-400 font-bold uppercase tracking-widest">{dbStatus.status === 'connected' ? 'CONNECTED' : 'DISCONNECTED'}</span>
                    </div>
                    <div className="bg-gray-950 p-3 rounded-xl border border-gray-700 flex items-center justify-between">
                        <span className="text-gray-500">Active Port:</span>
                        <span className="text-blue-400 font-bold">3004</span>
                    </div>
                </div>
            </div>

            {/* 3. WMS LAYERS SECTION */}
            <div className="bg-gray-800 rounded-3xl border border-gray-700 shadow-xl overflow-hidden">
                <div className="p-5 flex justify-between items-center border-b border-gray-700 bg-gray-800/50">
                    <div className="flex items-center gap-3">
                        <div className="p-2 bg-cyan-600/20 rounded-xl text-cyan-400 border border-cyan-500/20"><Globe size={20}/></div>
                        <div>
                            <h3 className="font-black text-white uppercase tracking-tight">Lớp bản đồ & Quy hoạch</h3>
                            <p className="text-[10px] text-gray-500 font-bold uppercase tracking-widest">WMS Server / XYZ Tileset</p>
                        </div>
                    </div>
                    <button onClick={() => openModal('LAYER')} className="bg-cyan-600 hover:bg-cyan-500 text-white px-5 py-2.5 rounded-2xl text-xs font-black flex items-center gap-2 transition-all shadow-xl shadow-cyan-950/30 active:scale-95">
                        <Plus size={18}/> THÊM LỚP DỮ LIỆU
                    </button>
                </div>
                <div className="overflow-x-auto">
                    <table className="w-full text-sm text-left">
                        <thead className="bg-gray-900 text-gray-400 uppercase text-[10px] font-black tracking-widest border-b border-gray-800">
                            <tr><th className="p-5">Tên hiển thị</th><th className="p-5">Loại</th><th className="p-5">Phân loại</th><th className="p-5">Trạng thái</th><th className="p-5 text-right">Quản trị</th></tr>
                        </thead>
                        <tbody className="divide-y divide-gray-700 text-gray-300">
                            {wmsLayers.map(l => (
                                <tr key={l.id} className="hover:bg-gray-700/30 transition-colors group">
                                    <td className="p-5">
                                        <div className="flex flex-col">
                                            <span className="font-black text-white text-base">{l.name}</span>
                                            <p className="text-[9px] text-gray-500 font-mono mt-0.5 truncate max-w-[200px]">{l.url}</p>
                                        </div>
                                    </td>
                                    <td className="p-5">
                                        <span className={`px-2 py-0.5 rounded text-[9px] font-black border ${l.type === 'XYZ' ? 'bg-orange-900/30 text-orange-400 border-orange-800' : 'bg-blue-900/30 text-blue-400 border-blue-800'}`}>
                                            {l.type || 'WMS'}
                                        </span>
                                    </td>
                                    <td className="p-5">
                                        <span className={`px-2 py-1 rounded-lg text-[9px] font-black uppercase ${l.category === 'PLANNING' ? 'bg-purple-900/40 text-purple-400 border border-purple-800' : 'bg-gray-900 text-gray-500 border border-gray-700'}`}>
                                            {l.category === 'PLANNING' ? 'Quy hoạch' : 'Chuyên đề'}
                                        </span>
                                    </td>
                                    <td className="p-5">
                                        <button onClick={() => adminService.updateWmsLayer({...l, visible: !l.visible}).then(loadData)} className={`flex items-center gap-2 px-3 py-1.5 rounded-xl border text-[10px] font-black uppercase transition-all ${l.visible ? 'bg-emerald-950/30 text-emerald-400 border-emerald-800' : 'bg-gray-900 text-gray-600 border-gray-800'}`}>
                                            {l.visible ? <Eye size={12}/> : <EyeOff size={12}/>}
                                            {l.visible ? 'Đang hiện' : 'Đang ẩn'}
                                        </button>
                                    </td>
                                    <td className="p-5">
                                        <div className="flex justify-end gap-2">
                                            <button onClick={() => openModal('LAYER', l)} className="p-2.5 bg-blue-600/10 text-blue-400 hover:bg-blue-600 hover:text-white rounded-xl transition-all shadow-lg"><Edit2 size={16}/></button>
                                            <button onClick={() => setConfirmDialog({ isOpen: true, title: 'Xác nhận xóa', message: `Bạn có chắc muốn gỡ bỏ lớp "${l.name}"?`, actionType: 'DELETE_WMS', targetId: l.id, targetName: l.name })} className="p-2.5 bg-red-600/10 text-red-400 hover:bg-red-600 hover:text-white rounded-xl transition-all shadow-lg"><Trash2 size={16}/></button>
                                        </div>
                                    </td>
                                </tr>
                            ))}
                        </tbody>
                    </table>
                </div>
            </div>

            {/* MODAL LAYER FORM */}
            {isModalOpen && modalType === 'LAYER' && (
                <div className="fixed inset-0 z-[1000] bg-black/95 backdrop-blur-md flex items-center justify-center p-4">
                    <div className="bg-[#1a1f2e] border border-gray-700 rounded-[2.5rem] w-full max-w-lg p-8 shadow-2xl animate-in zoom-in-95 duration-300">
                        <div className="flex justify-between items-center mb-8 border-b border-gray-800 pb-4">
                            <div>
                                <h3 className="text-2xl font-black text-white uppercase tracking-tighter">Cấu hình Lớp Dữ liệu</h3>
                                <p className="text-[10px] text-gray-500 font-bold uppercase tracking-widest mt-1">Vượt rào cản CORS & Tối ưu hiển thị</p>
                            </div>
                            <button onClick={() => setIsModalOpen(false)} className="text-gray-500 hover:text-white p-2 hover:bg-gray-800 rounded-full transition-all"><X size={28}/></button>
                        </div>

                        <div className="space-y-6 max-h-[65vh] overflow-y-auto pr-2 custom-scrollbar">
                            <div className="grid grid-cols-2 gap-3">
                                <div>
                                    <label className="text-[10px] text-gray-500 font-black uppercase mb-2 block tracking-widest">Loại nguồn</label>
                                    <div className="flex bg-gray-950 p-1 rounded-xl border border-gray-800">
                                        <button onClick={() => setFormData({...formData, type: 'WMS'})} className={`flex-1 py-2.5 text-[10px] font-black rounded-lg transition-all ${formData.type === 'WMS' ? 'bg-blue-600 text-white shadow-lg' : 'text-gray-600 hover:text-gray-400'}`}>WMS SERVER</button>
                                        <button onClick={() => setFormData({...formData, type: 'XYZ'})} className={`flex-1 py-2.5 text-[10px] font-black rounded-lg transition-all ${formData.type === 'XYZ' ? 'bg-orange-600 text-white shadow-lg' : 'text-gray-600 hover:text-gray-400'}`}>XYZ TILES</button>
                                    </div>
                                </div>
                                <div>
                                    <label className="text-[10px] text-gray-500 font-black uppercase mb-2 block tracking-widest">Phân nhóm</label>
                                    <div className="flex bg-gray-950 p-1 rounded-xl border border-gray-800">
                                        <button onClick={() => setFormData({...formData, category: 'STANDARD'})} className={`flex-1 py-2.5 text-[10px] font-black rounded-lg transition-all ${formData.category === 'STANDARD' ? 'bg-gray-700 text-white' : 'text-gray-600 hover:text-gray-400'}`}>CHUYÊN ĐỀ</button>
                                        <button onClick={() => setFormData({...formData, category: 'PLANNING'})} className={`flex-1 py-2.5 text-[10px] font-black rounded-lg transition-all ${formData.category === 'PLANNING' ? 'bg-purple-600 text-white shadow-lg' : 'text-gray-600 hover:text-gray-400'}`}>QUY HOẠCH</button>
                                    </div>
                                </div>
                            </div>

                            <div>
                                <label className="text-[10px] text-gray-500 font-black uppercase mb-2 block tracking-widest">Tên hiển thị *</label>
                                <input className="w-full bg-gray-950 border border-gray-700 rounded-2xl p-4 text-white font-bold outline-none focus:border-blue-500" placeholder="VD: Quy hoạch phân khu..." value={formData.name || ''} onChange={e => setFormData({...formData, name: e.target.value})} />
                            </div>

                            <div className="p-4 bg-emerald-900/10 border border-emerald-800/30 rounded-2xl flex items-start gap-3">
                                <Shield size={18} className="text-emerald-500 mt-1 shrink-0" />
                                <div>
                                    <p className="text-[10px] text-emerald-400 font-black uppercase leading-tight">Tính năng Proxy tự động</p>
                                    <p className="text-[9px] text-emerald-500/80 mt-1 leading-relaxed">Dữ liệu bản đồ sẽ được tải qua Server trung gian của GeoMaster để đảm bảo không bị trình duyệt chặn (lỗi CORS).</p>
                                </div>
                            </div>

                            <div>
                                <label className="text-[10px] text-gray-500 font-black uppercase mb-2 block tracking-widest">Địa chỉ URL nguồn dữ liệu *</label>
                                <textarea className="w-full bg-gray-950 border border-gray-700 rounded-2xl p-4 text-white font-mono text-[10px] outline-none focus:border-cyan-500 h-24 resize-none leading-relaxed" placeholder={formData.type === 'XYZ' ? "https://domain.com/tiles/{z}/{x}/{y}.png" : "https://domain.com/geoserver/wms"} value={formData.url || ''} onChange={e => setFormData({...formData, url: e.target.value})} />
                                {formData.type === 'XYZ' && (
                                    <p className="text-[9px] text-orange-400 mt-2 italic font-bold">Lưu ý: URL phải chứa cấu trúc {'{z}/{x}/{y}'}.</p>
                                )}
                            </div>

                            {formData.type === 'WMS' && (
                                <div>
                                    <label className="text-[10px] text-gray-500 font-black uppercase mb-2 block tracking-widest">Lớp dữ liệu (Layers Name)</label>
                                    <input className="w-full bg-gray-950 border border-gray-700 rounded-2xl p-4 text-white font-mono text-xs outline-none focus:border-blue-500" placeholder="vd: hcm:thua_dat" value={formData.layers || ''} onChange={e => setFormData({...formData, layers: e.target.value})} />
                                </div>
                            )}

                            <div className="flex items-center gap-4 bg-gray-950 p-4 rounded-2xl border border-gray-800">
                                <div className="flex-1">
                                    <label className="text-[10px] text-gray-500 font-black uppercase block mb-1">Độ mờ lớp phủ (Opacity)</label>
                                    <input type="range" min="0" max="1" step="0.1" className="w-full accent-blue-500" value={formData.opacity || 0.8} onChange={e => setFormData({...formData, opacity: parseFloat(e.target.value)})} />
                                </div>
                                <span className="text-lg font-black text-blue-400 w-12 text-center">{Math.round((formData.opacity || 0.8) * 100)}%</span>
                            </div>
                        </div>

                        <div className="flex gap-4 mt-8 pt-6 border-t border-gray-800">
                            <button onClick={() => setIsModalOpen(false)} className="flex-1 py-4 text-gray-500 hover:text-white font-black text-xs uppercase tracking-widest transition-colors">Hủy bỏ</button>
                            <button onClick={handleSave} disabled={loading} className="flex-[2] bg-blue-600 hover:bg-blue-500 text-white py-4 rounded-2xl font-black text-xs shadow-xl flex items-center justify-center gap-2 transition-all active:scale-95 disabled:opacity-50 uppercase tracking-widest">
                                {loading ? <RefreshCw className="animate-spin" size={18}/> : <Save size={18}/>} LƯU CẤU HÌNH
                            </button>
                        </div>
                    </div>
                </div>
            )}

            {/* CONFIRMATION MODAL */}
            {confirmDialog.isOpen && (
                <div className="fixed inset-0 z-[1100] bg-black/90 backdrop-blur-md flex items-center justify-center p-4 animate-in fade-in duration-200">
                    <div className="bg-gray-800 rounded-2xl w-full max-w-sm border border-gray-700 shadow-2xl overflow-hidden">
                        <div className={`p-6 flex flex-col items-center text-center ${confirmDialog.isDangerous ? 'bg-red-950/20' : 'bg-orange-950/20'}`}>
                            <div className={`w-16 h-16 rounded-full flex items-center justify-center mb-4 ${confirmDialog.isDangerous ? 'bg-red-500 text-white' : 'bg-orange-500 text-white'}`}>
                                <ShieldAlert size={32} />
                            </div>
                            <h3 className="text-xl font-black text-white uppercase tracking-tight mb-2">{confirmDialog.title}</h3>
                            <p className="text-gray-400 text-sm leading-relaxed">{confirmDialog.message}</p>
                        </div>
                        <div className="p-4 bg-gray-900/50 flex gap-3">
                            <button onClick={() => setConfirmDialog(prev => ({ ...prev, isOpen: false }))} className="flex-1 py-3 text-sm font-bold text-gray-400 hover:text-white uppercase">Hủy bỏ</button>
                            <button onClick={executeAction} className={`flex-1 py-3 text-sm font-black rounded-xl uppercase shadow-lg ${confirmDialog.isDangerous ? 'bg-red-600 hover:bg-red-500 text-white' : 'bg-blue-600 hover:bg-blue-500 text-white'}`}>Xác nhận</button>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

export default LayerManager;
